@app.route('/api/milestones', methods=['GET'])
def get_milestones():
    """Fetch Kalshi events with milestones — see what game lifecycle data is available.
    Optional params: series (e.g. KXATPMATCH), event_ticker (specific event), status (open/closed/settled)"""
    try:
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated'}), 401

        series = request.args.get('series', '')
        event_ticker = request.args.get('event_ticker', '')
        status = request.args.get('status', 'open')

        # If specific event requested, fetch just that one
        if event_ticker:
            if not api_read_limiter.try_wait():
                return jsonify({'error': 'Rate limit — try again shortly'}), 429
            event_resp = kalshi_client.get_event(event_ticker, with_nested_markets=True)
            event = event_resp.get('event', event_resp)
            # Also fetch milestones via events list filtered to this series
            series_from_event = event_ticker.split('-')[0] if '-' in event_ticker else ''
            if not api_read_limiter.try_wait():
                return jsonify({'error': 'Rate limit — try again shortly'}), 429
            ms_resp = kalshi_client.get_events(status=status, with_milestones=True,
                                                series_ticker=series_from_event, limit=50)
            milestones = ms_resp.get('milestones', [])
            # Filter milestones related to this event
            related = [m for m in milestones
                       if event_ticker in (m.get('related_event_tickers', []) + m.get('primary_event_tickers', []))]
            return jsonify({
                'event': event,
                'milestones': related,
                'all_milestones_count': len(milestones),
            })

        # Fetch events with milestones for a series
        if not api_read_limiter.try_wait():
            return jsonify({'error': 'Rate limit — try again shortly'}), 429
        resp = kalshi_client.get_events(status=status, with_milestones=True,
                                         series_ticker=series or None, limit=50)
        events = resp.get('events', [])
        milestones = resp.get('milestones', [])

        # Enrich: for each event, find its milestones
        ms_by_event = {}
        for m in milestones:
            for et in m.get('related_event_tickers', []) + m.get('primary_event_tickers', []):
                ms_by_event.setdefault(et, []).append(m)

        summary = []
        for e in events:
            et = e.get('event_ticker', '')
            summary.append({
                'event_ticker': et,
                'title': e.get('title', ''),
                'status': e.get('status', ''),
                'open_time': e.get('open_time', ''),
                'close_time': e.get('close_time', ''),
                'expected_expiration_time': e.get('expected_expiration_time', ''),
                'milestones': ms_by_event.get(et, []),
                'market_count': len(e.get('markets', [])),
            })

        return jsonify({
            'events': summary,
            'total_events': len(events),
            'total_milestones': len(milestones),
            'raw_milestones': milestones[:10],  # First 10 raw for inspection
        })
    except Exception as e:
        import traceback
        return jsonify({'error': str(e), 'trace': traceback.format_exc()}), 500


# ─── API Tennis integration (replaces ESPN for tennis) ──────────────────────
_API_TENNIS_KEY = 'a12d0895ba334cfa37cc5e131a8f94c78f0cd5d2d3785a28f36fe2e3c564747f'
_api_tennis_cache = {'data': None, 'ts': 0}
_API_TENNIS_TTL = 20  # seconds

def _set_won(score_obj, player):
    """Check if a set has been won by 'first' or 'second' player."""
    s1 = int(score_obj.get('score_first', 0))
    s2 = int(score_obj.get('score_second', 0))
    if player == 'first':
        return (s1 >= 6 and s1 - s2 >= 2) or s1 == 7
    else:
        return (s2 >= 6 and s2 - s1 >= 2) or s2 == 7


def _fetch_api_tennis_scoreboard(tour_filter):
    """Fetch today's tennis matches from API Tennis and format as ESPN-like events.
    tour_filter: 'atp' or 'wta' — filters event_type_type accordingly."""
    import datetime as _dt
    now = time.time()

    # Compute dates upfront — needed for both fetch and tomorrow-prematch filter
    _utc_today = _dt.datetime.utcnow().date()
    _utc_yesterday = (_utc_today - _dt.timedelta(days=1)).isoformat()
    _utc_tomorrow = (_utc_today + _dt.timedelta(days=1)).isoformat()
    today = _utc_today.isoformat()

    # Cache: single fetch for both ATP+WTA, filter client-side
    if _api_tennis_cache['data'] and (now - _api_tennis_cache['ts']) < _API_TENNIS_TTL:
        all_matches = _api_tennis_cache['data']
    else:
        try:
            # Fetch yesterday + today + tomorrow to catch timezone boundary matches
            url = f'https://api.api-tennis.com/tennis/?method=get_fixtures&date_start={_utc_yesterday}&date_stop={_utc_tomorrow}&APIkey={_API_TENNIS_KEY}'
            resp = requests.get(url, timeout=8)
            resp.raise_for_status()
            result = resp.json()
            all_matches = result.get('result', [])
            if isinstance(all_matches, list):
                _api_tennis_cache['data'] = all_matches
                _api_tennis_cache['ts'] = now
            else:
                all_matches = []
        except Exception as e:
            print(f'⚠️ API Tennis fetch failed: {e}')
            all_matches = []

    # Filter by tour: ATP/WTA Singles + Challengers (no doubles, no ITF)
    # Kalshi has ATP, WTA, ATP Challenger, and WTA Challenger markets
    tour_lower = tour_filter.lower()
    def _tennis_match_filter(m):
        t = (m.get('event_type_type') or '').lower()
        if 'doubles' in t:
            return False
        if tour_lower == 'atp':
            return 'atp' in t or 'challenger men' in t
        else:  # wta
            return 'wta' in t or 'challenger women' in t
    filtered = [m for m in all_matches if _tennis_match_filter(m)]

    # Exclude pre-match games from tomorrow — only include live/finished matches from the extra day
    # This prevents showing future games that waste rate limit reads
    def _is_tomorrow_prematch(m):
        if m.get('event_date') != _utc_tomorrow:
            return False
        # Keep if actually live or finished
        if m.get('event_live') == '1':
            return False
        status = (m.get('event_status') or '').lower()
        if 'finished' in status or m.get('event_winner'):
            return False
        if status in ('interrupted', 'break time', 'retired', 'walkover', 'defaulted'):
            return False
        # Has scores with sets won = still in progress, keep it
        scores = m.get('scores', [])
        if scores and any(int(s.get('score_first', 0)) > 0 or int(s.get('score_second', 0)) > 0 for s in scores):
            return False
        return True  # Pre-match tomorrow game — exclude
    filtered = [m for m in filtered if not _is_tomorrow_prematch(m)]

    # Transform into ESPN-like event format for parseESPNGame()
    events = []
    for m in filtered:
        p1 = m.get('event_first_player', '')
        p2 = m.get('event_second_player', '')
        p1_abbr = _tennis_player_code(p1)
        p2_abbr = _tennis_player_code(p2)
        p1_all_codes = _tennis_player_all_codes(p1)
        p2_all_codes = _tennis_player_all_codes(p2)

        # Determine match state
        is_live = m.get('event_live') == '1'
        status_str = (m.get('event_status', '') or '').lower()
        result_str = m.get('event_final_result', '') or '-'
        winner = m.get('event_winner', '')

        if is_live:
            state = 'in'
        elif status_str in ('interrupted', 'break time', 'retired', 'walkover', 'defaulted'):
            # Match in progress but on break/interrupted — treat as live
            state = 'in'
        elif winner or 'finished' in status_str:
            state = 'post'
        elif result_str not in ('-', '0 - 0', ''):
            # Has a set result but check if match is truly complete
            # Best-of-3: need 2 sets won; Best-of-5: need 3 sets won
            scores = m.get('scores', [])
            p1_sets = sum(1 for s in scores if _set_won(s, 'first'))
            p2_sets = sum(1 for s in scores if _set_won(s, 'second'))
            if p1_sets >= 2 or p2_sets >= 2:
                state = 'post'
            else:
                state = 'in'  # incomplete match with scores = still in progress
        else:
            state = 'pre'

        # Parse set scores
        scores = m.get('scores', [])
        p1_sets_won = 0
        p2_sets_won = 0
        p1_set_parts = []
        p2_set_parts = []
        current_set = len(scores) or 1
        for s in scores:
            s1 = int(float(s.get('score_first', 0)))
            s2 = int(float(s.get('score_second', 0)))
            p1_set_parts.append(f'{s1}-{s2}')
            p2_set_parts.append(f'{s2}-{s1}')
            # A set is won at 6+ games with 2+ lead, or 7 (tiebreak)
            if (s1 >= 6 or s2 >= 6) and abs(s1 - s2) >= 2:
                if s1 > s2: p1_sets_won += 1
                else: p2_sets_won += 1
            elif s1 == 7 or s2 == 7:
                if s1 > s2: p1_sets_won += 1
                else: p2_sets_won += 1

        p1_set_str = ' '.join(p1_set_parts)
        p2_set_str = ' '.join(p2_set_parts)

        # Game score (current game points like "30-40")
        game_result = m.get('event_game_result', '') or ''
        game_score_display = game_result if game_result != '-' else ''

        # Period label
        if state == 'in':
            period_label = status_str if status_str else f'Set {current_set}'
        elif state == 'post':
            period_label = 'Final'
        else:
            period_label = ''

        # Date for matching — noon UTC avoids timezone day-boundary issues
        event_date = m.get('event_date', '')
        event_time = m.get('event_time', '')
        match_date_iso = f"{event_date}T12:00:00Z" if event_date else ''
        # Actual start time for pregame display (API Tennis times are UTC)
        start_time_iso = f"{event_date}T{event_time}:00Z" if event_date and event_time else ''

        # Tournament + round for display
        tournament = m.get('tournament_name', '')
        round_str = m.get('tournament_round', '') or ''

        # Status object matching ESPN format
        status_obj = {
            'type': {
                'state': state,
                'shortDetail': period_label,
            },
            'period': current_set,
            'displayClock': game_score_display,
        }

        # Serving indicator: store as custom field
        serving = m.get('event_serve', '') or ''

        events.append({
            'id': str(m.get('event_key', '')),
            'date': match_date_iso,
            '_start_time': start_time_iso,
            'name': f'{p1} vs {p2} ({tournament})',
            'shortName': f'{p1} vs {p2}',
            'status': status_obj,
            'competitions': [{
                'competitors': [
                    {
                        'homeAway': 'away',
                        'winner': winner == 'First Player',
                        'score': str(p1_sets_won),
                        'team': {
                            'abbreviation': p1_abbr,
                            'extraAbbrs': p1_all_codes,
                            'shortDisplayName': p1.split()[-1] if p1 else '',
                            'displayName': p1,
                            'logo': '',
                        },
                        'linescores': [{'value': int(float(s.get('score_first', 0)))} for s in scores],
                        'setScores': p1_set_str,
                    },
                    {
                        'homeAway': 'home',
                        'winner': winner == 'Second Player',
                        'score': str(p2_sets_won),
                        'team': {
                            'abbreviation': p2_abbr,
                            'extraAbbrs': p2_all_codes,
                            'shortDisplayName': p2.split()[-1] if p2 else '',
                            'displayName': p2,
                            'logo': '',
                        },
                        'linescores': [{'value': int(float(s.get('score_second', 0)))} for s in scores],
                        'setScores': p2_set_str,
                    },
                ],
            }],
            # Custom fields for enhanced display
            '_serving': serving,
            '_game_score': game_score_display,
            '_tournament': tournament,
            '_round': round_str,
        })

    return {'events': events}


@app.route('/api/scoreboard/<sport>', methods=['GET'])
def get_scoreboard(sport):
    """Proxy ESPN/API Tennis scoreboard to avoid CORS issues.
    Tennis uses API Tennis for better coverage; all other sports use ESPN."""
    sport_map = {
        'nba': 'basketball/nba',
        'nfl': 'football/nfl',
        'mlb': 'baseball/mlb',
        'nhl': 'hockey/nhl',
        'ncaab': 'basketball/mens-college-basketball',
        'ncaaw': 'basketball/womens-college-basketball',
        'ncaaf': 'football/college-football',
        'mls': 'soccer/usa.1',
        'epl': 'soccer/eng.1',
        'ucl': 'soccer/uefa.champions',
        'atp': 'tennis/atp',
        'wta': 'tennis/wta',
    }
    sport_path = sport_map.get(sport.lower())
    if not sport_path:
        return jsonify({'error': f'Unknown sport: {sport}'}), 400

    try:
        # Tennis: use API Tennis for live scores (much better coverage than ESPN)
        if sport.lower() in ('atp', 'wta') and _API_TENNIS_KEY:
            data = _fetch_api_tennis_scoreboard(sport.lower())
            return jsonify(data)

        url = f'https://site.api.espn.com/apis/site/v2/sports/{sport_path}/scoreboard'
        # NCAAB/NCAAW: groups=50 includes NIT/CBI/CIT games (default only shows conference tournaments)
        params = {}
        if sport.lower() in ('ncaab', 'ncaaw'):
            params['groups'] = '50'
        resp = requests.get(url, params=params, timeout=5)
        resp.raise_for_status()
        data = resp.json()

        return jsonify(data)
    except Exception as e:
        return jsonify({'error': str(e)}), 500


def _tennis_player_code(display_name: str) -> str:
    """Generate 3-letter Kalshi-style code from a player's full name.
    e.g. 'Ekaterina Alexandrova' → 'ALE', 'Coco Gauff' → 'GAU'"""
    if not display_name:
        return ''
    last = display_name.strip().split()[-1]
    return last[:3].upper() if len(last) >= 3 else last.upper()


def _tennis_player_all_codes(display_name: str) -> list:
    """Generate 3-letter codes from ALL name parts (>=3 chars).
    Kalshi may use any part of compound surnames like 'Boscardin Dias' → BOS or DIA."""
    if not display_name:
        return []
    codes = []
    for part in display_name.strip().split():
        if len(part) >= 3:
            code = part[:3].upper()
            if code not in codes:
                codes.append(code)
    return codes


def _flatten_tennis_scoreboard(data: dict) -> dict:
    """Transform ESPN tennis scoreboard so each match is a top-level event
    with competitors that have team.abbreviation (3-letter last-name code).
    This lets the frontend parseESPNGame() handle tennis like any team sport."""
    flat_events = []
    for ev in data.get('events', []):
        tournament = ev.get('name', '')
        for grp in ev.get('groupings', []):
            for comp in grp.get('competitions', []):
                competitors = comp.get('competitors', [])
                # Build match name from player last names
                names = []
                for c in competitors:
                    ath = c.get('athlete', {})
                    dn = ath.get('displayName', '')
                    if dn:
                        names.append(dn.split()[-1])
                match_name = ' vs '.join(names) if names else 'Match'

                # Compute sets won from linescores
                home_ls = []
                away_ls = []
                for c in competitors:
                    ls = [s.get('value', 0) for s in c.get('linescores', [])]
                    if c.get('homeAway') == 'home':
                        home_ls = ls
                    else:
                        away_ls = ls
                home_sets = sum(1 for i in range(min(len(home_ls), len(away_ls)))
                                if home_ls[i] > away_ls[i])
                away_sets = sum(1 for i in range(min(len(home_ls), len(away_ls)))
                                if away_ls[i] > home_ls[i])

                # Transform competitors to look like team-sport format
                xformed = []
                for c in competitors:
                    ath = c.get('athlete', {})
                    display_name = ath.get('displayName', '')
                    last_name = display_name.split()[-1] if display_name else ''
                    abbr = _tennis_player_code(display_name)
                    side = c.get('homeAway', '')
                    score = str(home_sets if side == 'home' else away_sets)
                    # Build set scores string for display: "7-5 6-4 3-2"
                    set_scores_str = ''
                    paired_ls = home_ls if side == 'home' else away_ls
                    other_ls = away_ls if side == 'home' else home_ls
                    set_parts = []
                    for i in range(min(len(paired_ls), len(other_ls))):
                        set_parts.append(f'{int(paired_ls[i])}-{int(other_ls[i])}')
                    set_scores_str = ' '.join(set_parts)
                    xformed.append({
                        'homeAway': side,
                        'winner': c.get('winner', False),
                        'score': score,
                        'team': {
                            'abbreviation': abbr,
                            'shortDisplayName': last_name,
                            'displayName': display_name,
                            'logo': (ath.get('headshot') or {}).get('href', '')
                                    or (ath.get('flag') or {}).get('href', ''),
                        },
                        'linescores': c.get('linescores', []),
                        'setScores': set_scores_str,
                    })

                flat_events.append({
                    'id': comp.get('id', ''),
                    'date': comp.get('date') or comp.get('startDate') or ev.get('date', ''),
                    'name': f'{match_name} ({tournament})',
                    'shortName': match_name,
                    'status': comp.get('status', {}),
                    'competitions': [{
                        'competitors': xformed,
                        'venue': comp.get('venue', {}),
                    }],
                })
    data['events'] = flat_events
    return data


# ─── ESPN Box Score proxy for live player stats ───────────────────────────────
_boxscore_cache = {}  # {game_id: {'data': {...}, 'ts': float}}
_BOXSCORE_TTL = 30    # seconds

@app.route('/api/boxscore/<sport>/<game_id>', methods=['GET'])
def get_boxscore(sport, game_id):
    """
    Proxy ESPN boxscore API to get live per-player stats.
    Returns a simplified dict: {player_name: {pts, reb, ast, stl, blk, ...}}.
    Cached for 30 seconds to avoid hammering ESPN.
    """
    sport_map = {
        'nba': 'basketball/nba',
        'ncaab': 'basketball/mens-college-basketball',
        'ncaaw': 'basketball/womens-college-basketball',
        'nfl': 'football/nfl',
        'mlb': 'baseball/mlb',
        'nhl': 'hockey/nhl',
    }
    sport_path = sport_map.get(sport.lower())
    if not sport_path:
        return jsonify({'error': f'Unknown sport: {sport}'}), 400

    cache_key = f'{sport}_{game_id}'
    now = time.time()
    cached = _boxscore_cache.get(cache_key)
    if cached and now - cached['ts'] < _BOXSCORE_TTL:
        return jsonify(cached['data'])

    try:
        url = f'https://site.api.espn.com/apis/site/v2/sports/{sport_path}/summary?event={game_id}'
        resp = requests.get(url, timeout=8)
        resp.raise_for_status()
        raw = resp.json()

        players = {}
        # Parse boxscore from summary
        for team_box in raw.get('boxscore', {}).get('players', []):
            team_name = team_box.get('team', {}).get('abbreviation', '?')
            for stat_group in team_box.get('statistics', []):
                labels = stat_group.get('labels', [])   # e.g. ['MIN','FG','3PT','FT','OREB','DREB','REB','AST','STL','BLK','TO','PF','PTS']
                for athlete in stat_group.get('athletes', []):
                    name = athlete.get('athlete', {}).get('displayName', '?')
                    short_name = athlete.get('athlete', {}).get('shortName', name)
                    stats = athlete.get('stats', [])
                    stat_dict = {}
                    for i, label in enumerate(labels):
                        if i < len(stats):
                            stat_dict[label.lower()] = stats[i]
                    stat_dict['team'] = team_name
                    stat_dict['name'] = name
                    stat_dict['short_name'] = short_name
                    # Use lowercase full name as key for easy lookup
                    players[name.lower()] = stat_dict

        # Also include game status
        game_status = ''
        header = raw.get('header', {})
        competitions = header.get('competitions', [{}])
        if competitions:
            game_status = competitions[0].get('status', {}).get('type', {}).get('shortDetail', '')

        result = {
            'players': players,
            'game_status': game_status,
            'game_id': game_id,
        }
        _boxscore_cache[cache_key] = {'data': result, 'ts': now}
        return jsonify(result)

    except Exception as e:
        return jsonify({'error': str(e), 'players': {}}), 200


@app.route('/api/fills', methods=['GET'])
def get_fills():
    """Get recent fills/trades"""
    try:
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated'}), 401
        
        ticker = request.args.get('ticker')
        if not api_read_limiter.try_wait():
            return jsonify({'error': 'Rate limit — try again shortly'}), 429
        fills = kalshi_client.get_fills(ticker=ticker)
        return jsonify(fills)
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500


# ─── Dual Arb Bot System ──────────────────────────────────────────────────────
# Strategy: place LIMIT BUY orders on both YES and NO sides simultaneously.
# Both orders sit in the order book as bids (market maker = no taker fees).
# As price volatility causes each side to fill, profit is locked in on settlement.
# Stop loss: if one side fills and the other side's bid drops X cents, market-sell
# the filled side to exit (market order guarantees execution despite taker fees).

active_bots = {}  # bot_id -> bot_config
trade_history = []  # completed/stopped bots log (newest first)
_opening_lines = {}  # ticker -> {'yes_price': int, 'captured_at': float} — pre-game closing line
_pending_maker_sells = {}  # sell_id -> {oid, ticker, side, qty, posted_price, posted_at, reason}

# ─── Activity Log ─────────────────────────────────────────────────────────────
LOG_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'activity_log.jsonl')
_log_lock = threading.Lock()

def bot_log(event: str, bot_id: str = '', details: dict = None, level: str = 'INFO'):
    """Write a structured log entry. Every bot decision gets logged here.
    
    Events:
      BOT_CREATED, ORDER_PLACED, ORDER_CANCELLED, ORDER_FILLED,
      FAV_POSTED, FAV_FILLED, DOG_POSTED, FAV_REPOSTED, FAV_STALE_CANCELLED,
      SL_TRIGGERED, SL_BLOCKED_STALE, SL_FIRED, SL_FAILED,
      TP_TRIGGERED, TP_FIRED, TP_FAILED,
      REPOST, RESIZE, SETTLEMENT, MARKET_SETTLED,
      WATCH_FILLED, WATCH_SL, WATCH_TP, WATCH_SETTLED,
      REPEAT_STARTED, REPEAT_TIMEOUT,
      MONITOR_CYCLE, ERROR
    """
    entry = {
        'ts': datetime.now(timezone.utc).isoformat(),
        'epoch': time.time(),
        'event': event,
        'level': level,
        'bot_id': bot_id,
    }
    # Snapshot bot state if it exists
    if bot_id and bot_id in active_bots:
        b = active_bots[bot_id]
        entry['bot_snapshot'] = {
            'type': b.get('type', 'arb'),
            'ticker': b.get('ticker'),
            'status': b.get('status'),
            'side': b.get('side'),
            'yes_price': b.get('yes_price'),
            'no_price': b.get('no_price'),
            'entry_price': b.get('entry_price'),
            'quantity': b.get('quantity'),
            'yes_fill_qty': b.get('yes_fill_qty', 0),
            'no_fill_qty': b.get('no_fill_qty', 0),
            'fill_qty': b.get('fill_qty', 0),
            'live_bid': b.get('live_bid'),
            'stop_loss_cents': b.get('stop_loss_cents'),
            'game_phase': b.get('game_phase'),
            'fav_side': b.get('fav_side'),
            'profit_per': b.get('profit_per'),
            'repost_count': b.get('repost_count', 0),
            'fair_value_cents': b.get('fair_value_cents'),
        }
    if details:
        entry['details'] = details
    
    with _log_lock:
        try:
            with open(LOG_FILE, 'a') as f:
                f.write(json.dumps(entry, default=str) + '\n')
        except Exception as e:
            print(f'⚠ bot_log write failed: {e}')
    
    # Also print a compact summary to console
    det_str = f' | {details}' if details else ''
    print(f'📋 [{level}] {event} {bot_id}{det_str}')

# ─── State Persistence ────────────────────────────────────────────────────────
DATA_FILE   = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'data.json')
TRADES_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'trades.jsonl')

_save_lock = threading.Lock()

applied_migrations: list = []  # tracks which migrations have run

# ─── Kalshi Fee Calculation ──────────────────────────────────────────────────
# Maker fee = ceil(0.0175 * C * P * (1-P) * 100) cents per side
# Taker fee = ceil(0.07   * C * P * (1-P) * 100) cents per side
# Arb bots use resting limit orders → maker fee on both legs.
KALSHI_MAKER_RATE = 0.0175
KALSHI_TAKER_RATE = 0.07

def _kalshi_side_fee_cents(price_cents: int, qty: int) -> int:
    """Maker fee for one side in cents (rounded up)."""
    P = price_cents / 100
    raw_dollars = KALSHI_MAKER_RATE * qty * P * (1 - P)
    return _math.ceil(raw_dollars * 100)  # cents, rounded up

def _kalshi_taker_side_fee_cents(price_cents: int, qty: int) -> int:
    """Taker fee for one side in cents (rounded up)."""
    P = price_cents / 100
    raw_dollars = KALSHI_TAKER_RATE * qty * P * (1 - P)
    return _math.ceil(raw_dollars * 100)  # cents, rounded up

def kalshi_fee_cents(yes_price: int, no_price: int, qty: int) -> int:
    """Total Kalshi maker fee for both legs of an arb trade, in cents."""
    return _kalshi_side_fee_cents(yes_price, qty) + _kalshi_side_fee_cents(no_price, qty)

def _smart_mode_should_repeat(bot, cycle_pnl, exit_type=None):
    """Smart mode repeat decision. Returns (should_repeat: bool, reason: str).

    Apex MM: uses cumulative loss limit — stop when total realized P&L drops
    below negative threshold (loss_limit_cents). MMs naturally have small losses
    from wall fills and stop-loss exits; consecutive-loss counting kills them.

    Other bots: stop after 2 consecutive losses (legacy behavior)."""
    # General stop flag (from /api/bot/stop) — prevents next repeat for ANY bot type
    if bot.get('_stop_pending'):
        return False, 'manual_stop'
    if not bot.get('smart_mode'):
        return None, ''  # not smart mode, use normal repeat logic
    if bot.get('_smart_stopped'):
        return False, 'manual_stop'

    # ── Apex MM: cumulative loss limit ──
    if bot.get('type') == 'apex_mm':
        total_pnl = bot.get('realized_pnl_cents', 0)
        loss_limit = bot.get('loss_limit_cents', 0)
        # loss_limit_cents is stored as positive (e.g., 50 = stop after losing 50c)
        if loss_limit > 0 and total_pnl <= -loss_limit:
            bot['_smart_stopped'] = True
            bot['_smart_stop_reason'] = 'loss_limit'
            return False, f'loss_limit (pnl={total_pnl}c <= -{loss_limit}c)'
        # Track wins/losses for stats display (but don't stop on consecutive losses)
        if cycle_pnl < 0:
            bot['consecutive_losses'] = bot.get('consecutive_losses', 0) + 1
            bot['_smart_losses'] = bot.get('_smart_losses', 0) + 1
        elif cycle_pnl > 0:
            bot['consecutive_losses'] = 0
            bot['_smart_wins'] = bot.get('_smart_wins', 0) + 1
        return True, f'mm_continue (pnl={total_pnl}c, limit=-{loss_limit}c)'

    # ── Other bots: consecutive loss stop ──
    losses = bot.get('consecutive_losses', 0)
    if cycle_pnl < 0:
        losses += 1
        bot['consecutive_losses'] = losses
        bot['_smart_losses'] = bot.get('_smart_losses', 0) + 1
        if losses >= 2:
            bot['_smart_stopped'] = True
            bot['_smart_stop_reason'] = 'losses'
            return False, f'smart_stop_{losses}L'
        return True, f'smart_loss_{losses}L_continue'
    else:
        bot['consecutive_losses'] = 0
        bot['_smart_wins'] = bot.get('_smart_wins', 0) + 1
        return True, 'smart_win'


# ─── Data Migrations ─────────────────────────────────────────────────────────
# To modify trade_history data permanently, add a migration function below.
# Each migration runs ONCE after load_state(), modifies trade_history in memory,
# then save_state() persists the changes. The migration name is recorded in
# applied_migrations so it never re-runs.
#
# HOW TO ADD A NEW MIGRATION:
#   1. Write a function: def _migrate_NNN_description():
#      - It can read/modify the global trade_history list directly
#      - Print what it did
#   2. Add an entry to the MIGRATIONS list: ('NNN_description', _migrate_NNN_description)
#   3. Restart the server — it runs automatically
#
# The server must be restarted for migrations to apply. They run in order.
# ─────────────────────────────────────────────────────────────────────────────

def _migrate_001_recalc_fees():
    """Recalculate fee_cents on all historical trades using correct Kalshi maker formula.
    Also adjusts profit_cents/loss_cents to include fees."""
    global trade_history
    updated = 0
    for t in trade_history:
        yes_p = t.get('yes_price') or t.get('yes_fill_price')
        no_p = t.get('no_price') or t.get('no_fill_price')
        qty = t.get('quantity') or t.get('contracts') or 100
        if not yes_p or not no_p:
            continue
        yes_p = int(yes_p)
        no_p = int(no_p)
        qty = int(qty)
        fee = kalshi_fee_cents(yes_p, no_p, qty)
        old_fee = t.get('fee_cents', 0) or 0
        if old_fee == fee:
            continue  # already correct
        # Undo old fee from profit/loss, apply new fee
        if 'profit_cents' in t:
            t['profit_cents'] = int(t['profit_cents']) + int(old_fee) - fee
        if 'loss_cents' in t and int(t.get('loss_cents', 0)) > 0:
            t['loss_cents'] = int(t['loss_cents']) - int(old_fee) + fee
        t['fee_cents'] = fee
        updated += 1
    print(f'📊 Migration 001: recalculated fees on {updated} trades')

def _migrate_002_remove_mar12():
    """Remove all March 12 trades — they're from the old timeout-sell system
    before the amend system was implemented. Data is inaccurate."""
    global trade_history, pnl_resets
    before = len(trade_history)
    trade_history = [t for t in trade_history
                     if datetime.fromtimestamp(t.get('timestamp', 0)).strftime('%Y-%m-%d') != '2026-03-12']
    removed = before - len(trade_history)
    pnl_resets.pop('2026-03-12', None)
    print(f'📊 Migration 002: removed {removed} Mar 12 trades (old system), cleared Mar 12 reset')

def _migrate_003_reclean_mar12():
    """Re-delete Mar 12 trades that got restored from trades.jsonl.
    Migration 002 only cleaned data.json, not trades.jsonl, so restarts re-added them."""
    global trade_history, pnl_resets
    before = len(trade_history)
    trade_history = [t for t in trade_history
                     if datetime.fromtimestamp(t.get('timestamp', 0)).strftime('%Y-%m-%d') != '2026-03-12']
    removed = before - len(trade_history)
    pnl_resets.pop('2026-03-12', None)
    print(f'📊 Migration 003: re-cleaned {removed} Mar 12 trades (were restored from trades.jsonl)')

def _migrate_004_fix_completed_labels():
    """Fix trades labeled 'completed' that actually lost money.
    A true completed arb (both legs filled < 100c) always profits.
    If profit < 0 or loss > 0, it was amended/timed out, not completed."""
    global trade_history
    fixed = 0
    for t in trade_history:
        if t.get('result') != 'completed':
            continue
        p = t.get('profit_cents', 0) or 0
        l = t.get('loss_cents', 0) or 0
        if p >= 0 and l <= 0:
            continue  # genuinely completed
        # Determine correct label based on exit_via
        exit_via = t.get('exit_via', '')
        if exit_via == 'timeout_amend' or exit_via == 'cancel_amend':
            t['result'] = 'amended'
        elif p < 0:
            # Negative profit, no exit_via — was amended but not tagged
            t['result'] = 'amended'
            # Normalize: move negative profit into loss_cents
            t['loss_cents'] = abs(p)
            t['profit_cents'] = 0
        elif l > 0:
            # Has loss_cents on a "completed" — was amended
            t['result'] = 'amended'
        fixed += 1
    print(f'📊 Migration 004: relabeled {fixed} mislabeled "completed" trades → "amended"')

def _migrate_005_fix_rebalancer_pnl():
    """Fix rebalancer_scrape and rebalancer_enhance trades with missing/incorrect P&L fields."""
    global trade_history
    fixed = 0
    for t in trade_history:
        if t.get('result') == 'rebalancer_scrape':
            loss = t.get('loss_cents', 0) or 0
            if loss < 0:
                # Was profitable but stored as negative loss
                t['profit_cents'] = abs(loss)
                t['loss_cents'] = 0
                fixed += 1
            elif 'profit_cents' not in t:
                t['profit_cents'] = 0
                fixed += 1
        elif t.get('result') == 'rebalancer_enhance':
            recovery = t.get('recovery_cents', 0) or 0
            if 'profit_cents' not in t:
                t['profit_cents'] = recovery
                t['loss_cents'] = 0
                fixed += 1
    print(f'📊 Migration 005: fixed P&L on {fixed} rebalancer trades')

# Master migration list — add new migrations at the bottom
def _migrate_006_dedup_rung_trades():
    """Remove duplicate rung completion trades caused by race condition.
    _check_apex_rung_completions was called from 3 places, recording the same
    rung twice before _profit_recorded flag was saved. Dedup by (bot_id, prices, qty, result, exit_via)."""
    global trade_history
    from collections import defaultdict
    before = len(trade_history)
    by_bot = defaultdict(list)
    for t in trade_history:
        by_bot[t.get('bot_id', 'unknown')].append(t)
    cleaned = []
    for bot_id, bt in by_bot.items():
        bt.sort(key=lambda x: x.get('timestamp', 0))
        seen = set()
        for t in bt:
            key = (t.get('yes_price'), t.get('no_price'), t.get('quantity'),
                   t.get('result'), t.get('exit_via'))
            if key in seen:
                continue
            seen.add(key)
            cleaned.append(t)
    cleaned.sort(key=lambda t: t.get('timestamp', 0), reverse=True)
    trade_history = cleaned
    removed = before - len(trade_history)
    print(f'📊 Migration 006: removed {removed} duplicate rung trades ({before} → {len(trade_history)})')

def _migrate_007_backfill_anchor_depth():
    """Backfill anchor_depth on historical phantom trades that lack it."""
    global trade_history
    updated = 0
    for t in trade_history:
        if t.get('bot_category') not in ('anchor_dog', 'anchor_ladder'):
            continue  # keep anchor_ladder for historical trade migration
        if t.get('anchor_depth') is not None:
            continue
        t['anchor_depth'] = 5
        updated += 1
    print(f'📊 Migration 007: backfilled anchor_depth on {updated} phantom trades')

def _migrate_008_fix_sport_labels():
    """Fix sport labels for ATP/WTA Challenger tickers that mapped to 'Other'."""
    global trade_history
    updated = 0
    for t in trade_history:
        ticker = (t.get('ticker') or '').upper()
        series = ticker.split('-')[0] if ticker else ''
        if t.get('sport') == 'Other' and ('CHALLENGERMATCH' in series or 'CHALLENGE' in series):
            if 'ATP' in series:
                t['sport'] = 'Tennis'
                updated += 1
            elif 'WTA' in series:
                t['sport'] = 'Tennis'
                updated += 1
    print(f'📊 Migration 008: fixed sport labels on {updated} trades (Challenger → Tennis)')

MIGRATIONS = [
    ('001_recalc_fees', _migrate_001_recalc_fees),
    ('002_remove_mar12', _migrate_002_remove_mar12),
    ('003_reclean_mar12', _migrate_003_reclean_mar12),
    ('004_fix_completed_labels', _migrate_004_fix_completed_labels),
    ('005_fix_rebalancer_pnl', _migrate_005_fix_rebalancer_pnl),
    ('006_dedup_rung_trades', _migrate_006_dedup_rung_trades),
    ('007_backfill_anchor_depth', _migrate_007_backfill_anchor_depth),
    ('008_fix_sport_labels', _migrate_008_fix_sport_labels),
]

def run_migrations():
    """Run any pending data migrations after load_state(). Saves once if any ran."""
    global applied_migrations
    ran = 0
    for name, func in MIGRATIONS:
        if name in applied_migrations:
            continue
        print(f'🔄 Running migration: {name}')
        try:
            func()
            applied_migrations.append(name)
            ran += 1
        except Exception as e:
            print(f'❌ Migration {name} failed: {e}')
            break  # stop on failure — don't skip
    if ran:
        save_state()
        # Also rewrite trades.jsonl so deleted trades don't come back on restart
        try:
            with open(TRADES_FILE, 'w') as _tf:
                for t in trade_history:
                    _tf.write(json.dumps(t, default=str) + '\n')
            print(f'📝 trades.jsonl rewritten after migrations ({len(trade_history)} trades)')
        except Exception as _je:
            print(f'⚠ trades.jsonl rewrite failed: {_je}')
        print(f'✅ {ran} migration(s) applied and saved')
    else:
        print('✅ No pending migrations')


def save_state():
    """Persist active_bots and trade_history to disk so they survive restarts.
    Uses atomic write (temp → rename) so a crash mid-write never corrupts data.json."""
    with _save_lock:
        try:
            tmp = DATA_FILE + '.tmp'
            with open(tmp, 'w') as f:
                json.dump({
                    'active_bots': active_bots,
                    'trade_history': trade_history,
                    'session_pnl': session_pnl,
                    'opening_lines': _opening_lines,
                    'pnl_resets': pnl_resets,
                    'applied_migrations': applied_migrations,
                    'pending_maker_sells': _pending_maker_sells,
                }, f, indent=2, default=str)
            os.replace(tmp, DATA_FILE)  # atomic — no partial-write corruption
        except Exception as e:
            print(f'⚠ save_state: {e}')

BACKUP_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'data_backup.json')

def load_state():
    """Load persisted bots and history from disk.
    Also merges trades.jsonl to recover any trades recorded after the last save_state()."""
    global active_bots, trade_history, session_pnl, _opening_lines, pnl_resets, applied_migrations, _pending_maker_sells
    try:
        if os.path.exists(DATA_FILE):
            with open(DATA_FILE, 'r') as f:
                data = json.load(f)
            active_bots = data.get('active_bots', {})
            trade_history = data.get('trade_history', [])
            _opening_lines = data.get('opening_lines', {})
            applied_migrations = data.get('applied_migrations', [])
            # Load per-day resets (or migrate from legacy single float)
            saved_resets = data.get('pnl_resets')
            if isinstance(saved_resets, dict):
                pnl_resets = saved_resets
            else:
                # Legacy: single pnl_reset_since float
                old_val = float(data.get('pnl_reset_since', 0))
                if old_val > 0:
                    from datetime import datetime as _dt
                    old_day = _dt.fromtimestamp(old_val).date().isoformat()
                    pnl_resets = {old_day: old_val}
                else:
                    pnl_resets = {}
            saved = data.get('session_pnl')
            if saved:
                for k in ('gross_profit_cents','gross_loss_cents','completed_bots','stopped_bots'):
                    if k in saved:
                        session_pnl[k] = saved[k]
            # Restore pending maker sells so they survive restarts
            _saved_sells = data.get('pending_maker_sells', {})
            if _saved_sells:
                _pending_maker_sells.update(_saved_sells)
                # Subscribe tickers to WS so sell-follow gets price ticks
                _sell_tickers = set(v.get('ticker','') for v in _saved_sells.values() if v.get('ticker'))
                for _st in _sell_tickers:
                    try:
                        if ws_manager:
                            ws_manager.subscribe(_st)
                    except Exception:
                        pass
                print(f'📤 Restored {len(_saved_sells)} pending maker sells (subscribed {len(_sell_tickers)} tickers)')
            print(f'✅ Loaded: {len(active_bots)} bots, {len(trade_history)} history, {len(_opening_lines)} opening lines, resets={pnl_resets}')
            # Clear transient runtime flags that should never persist across restarts.
            # _completion_in_progress is set during the multi-phase apex completion flow
            # and cleared in a finally block — but if the server restarts mid-completion,
            # the flag stays True in data.json and permanently blocks re-entry.
            _transient_cleared = 0
            for _bid, _bot in active_bots.items():
                # Clear ALL transient thread flags — threads are dead after restart
                _any_cleared = False
                for _flag in ('_completion_in_progress', '_ws_fill_handling', '_bot_completed',
                              '_completion_repeat_processed', '_sweep_thread_running',
                              '_hedge_fired'):
                    if _bot.get(_flag):
                        _bot[_flag] = False
                        _any_cleared = True
                # Keep old order IDs for startup fill recovery — pruning them before
                # fill recovery causes missed fills to become undetectable orphans.
                # WS ghost fills are handled by the verify-before-hedge path instead.
                # Pruning happens AFTER fill recovery in _run_startup().
                # DON'T blindly reset fill counts — check Kalshi position instead
                # Old code reset to 0 and hoped monitor would re-detect, but that
                # wiped real fills from old order IDs that got cleared above.
                # Apex MM: clear stale fill counts when flat (net=0)
                if _bot.get('type') == 'apex_mm' and _bot.get('net_yes', 0) == 0 and _bot.get('net_no', 0) == 0:
                    for _sk in ('yes_orders', 'no_orders'):
                        for _prc, _lv in _bot.get(_sk, {}).items():
                            if _lv.get('fill_qty', 0) > 0:
                                _lv['fill_qty'] = 0
                                _any_cleared = True
                # Apex MM: detect phantom inventory (net > 0 but avg_cost = 0)
                if _bot.get('type') == 'apex_mm':
                    _ny = _bot.get('net_yes', 0)
                    _nn = _bot.get('net_no', 0)
                    _ay = _bot.get('avg_yes_cost', 0)
                    _an = _bot.get('avg_no_cost', 0)
                    if (_ny > 0 and _ay == 0) or (_nn > 0 and _an == 0):
                        print(f'🔧 APEX MM PHANTOM INV: {_bid[:40]} net_yes={_ny} avg={_ay} net_no={_nn} avg={_an} → clearing phantom')
                        _bot['net_yes'] = 0
                        _bot['net_no'] = 0
                        _bot['avg_yes_cost'] = 0
                        _bot['avg_no_cost'] = 0
                        _bot['total_yes_cost'] = 0
                        _bot['total_no_cost'] = 0
                        _any_cleared = True
                if _any_cleared:
                    _transient_cleared += 1
                    print(f'🔧 STARTUP FIX: {_bid[:40]} cleared stuck thread flags + stale order IDs')
            if _transient_cleared:
                print(f'🔧 Cleared {_transient_cleared} stuck transient flags on startup')
            # Write a backup on startup so we can always recover
            if trade_history:
                try:
                    import shutil
                    shutil.copy2(DATA_FILE, BACKUP_FILE)
                    print(f'📦 Backup written: {len(trade_history)} trades')
                except Exception as be:
                    print(f'⚠ backup: {be}')
    except Exception as e:
        print(f'⚠ load_state: {e}')

    # ── Merge trades.jsonl: recover trades written after last save_state ──
    if os.path.exists(TRADES_FILE):
        try:
            existing_ids = set()
            for t in trade_history:
                tid = t.get('_trade_id') or f"{t.get('timestamp',0)}_{t.get('bot_id','')}"
                existing_ids.add(tid)
            recovered = 0
            with open(TRADES_FILE, 'r') as _tf:
                for line in _tf:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        t = json.loads(line)
                        tid = t.get('_trade_id') or f"{t.get('timestamp',0)}_{t.get('bot_id','')}"
                        if tid not in existing_ids:
                            trade_history.append(t)
                            existing_ids.add(tid)
                            recovered += 1
                    except Exception:
                        pass
            if recovered:
                trade_history.sort(key=lambda t: t.get('timestamp', 0), reverse=True)
                print(f'🔁 Recovered {recovered} trades from trades.jsonl (were missing from data.json)')
            # Rewrite trades.jsonl from the merged list to prune duplicates/old entries
            with open(TRADES_FILE, 'w') as _tf:
                for t in trade_history:
                    _tf.write(json.dumps(t, default=str) + '\n')
        except Exception as _jle:
            print(f'⚠ trades.jsonl merge failed: {_jle}')

    # ── Deduplicate: remove duplicate trades for the same bot_id within 60s ──
    # Multiple paths (WS handler, monitor REST, monitor timeout amend) can record
    # the same arb completion. Keep the FIRST entry (earliest timestamp) per bot_id
    # within any 60-second window, remove all others.
    # Also convert legacy 'timeout_exit_*' results to 'completed' since amend
    # completes the arb — the old result type is vestigial.
    _seen_bots = {}  # bot_id → timestamp of kept entry
    _remove_idx = set()
    for i, t in enumerate(trade_history):
        bid = t.get('bot_id', '')
        ts = t.get('timestamp', 0)
        if not bid:
            continue
        # Convert legacy timeout_exit_* to completed
        if t.get('result', '').startswith('timeout_exit'):
            t['result'] = 'completed'
            if not t.get('exit_via'):
                t['exit_via'] = 'timeout_amend'
        # Rung completions are separate trades per rung — never dedup them
        if t.get('exit_via') in ('ladder_arb_rung_complete', 'arb_complete'):
            continue
        if t.get('fill_source') == 'apex2_rung':
            continue
        # Phantom repeating bots reuse bot_id across runs — never dedup them
        if t.get('bot_category') in ('anchor_dog', 'anchor_ladder'):
            continue
        # Apex MM round trips are frequent, same bot_id — never dedup
        if t.get('fill_source', '').startswith('apex_mm'):
            continue
        if bid in _seen_bots and abs(ts - _seen_bots[bid]) < 60:
            _remove_idx.add(i)
        else:
            _seen_bots[bid] = ts
    if _remove_idx:
        trade_history = [t for i, t in enumerate(trade_history) if i not in _remove_idx]
        print(f'🧹 Deduped: removed {len(_remove_idx)} duplicate trade entries')
        save_state()  # persist cleaned data immediately

    # ── Recalculate session_pnl from trades to ensure consistency across restarts ──
    _day_key = session_pnl.get('day_key', '')
    _reset_ts = pnl_resets.get(_day_key, session_pnl.get('session_start', 0))
    _recalc_profit = 0
    _recalc_loss = 0
    _recalc_completed = 0
    _recalc_stopped = 0
    for t in trade_history:
        if t.get('timestamp', 0) < _reset_ts:
            continue
        p = t.get('profit_cents', 0)
        l = t.get('loss_cents', 0)
        if p > 0:
            _recalc_profit += p
        if l > 0:
            _recalc_loss += l
        result = t.get('result', '')
        if 'completed' in result or 'win' in result:
            _recalc_completed += 1
        elif 'sellback' in result or 'dual_exit' in result or 'ceiling_exit' in result or 'manual' in result or 'settled' in result:
            _recalc_stopped += 1
    _old_profit = session_pnl.get('gross_profit_cents', 0)
    _old_loss = session_pnl.get('gross_loss_cents', 0)
    if abs(_recalc_profit - _old_profit) > 5 or abs(_recalc_loss - _old_loss) > 5:
        print(f'🔧 P&L RECALC: profit {_old_profit}→{_recalc_profit} loss {_old_loss}→{_recalc_loss} (from trades.jsonl)')
        session_pnl['gross_profit_cents'] = _recalc_profit
        session_pnl['gross_loss_cents'] = _recalc_loss
        session_pnl['completed_bots'] = _recalc_completed
        session_pnl['stopped_bots'] = _recalc_stopped
        save_state()

# ─── Rate Limiter (Upgrade #7: API rate limit guard) ──────────────────────────
class RateLimiter:
    """Burst rate limiter — fires up to `burst` requests instantly within a
    1-second window, then hard-blocks until the next window starts.
    No delay between requests within the burst (preserves 1ms latency).
    Reserves 2 tokens for priority hedge operations so they never queue."""
    RESERVED_HEDGE_TOKENS = 2  # always keep 2 slots free for hedges

    def __init__(self, burst: int = 10):
        self.burst = burst
        self._count = 0
        self._window_start = time.time()
        self._lock = threading.Lock()
        # Usage tracking
        self._total_calls = 0
        self._calls_last_min = 0
        self._min_start = time.time()

    def get_usage(self):
        """Return calls/min and current burst count."""
        with self._lock:
            now = time.time()
            if now - self._min_start >= 60:
                self._calls_last_min = 0
                self._min_start = now
            return {'calls_per_min': self._calls_last_min, 'burst_used': self._count, 'burst_max': self.burst}

    def wait(self, priority=False):
        while True:
            with self._lock:
                now = time.time()
                elapsed = now - self._window_start
                if elapsed >= 1.0:
                    # New window — reset counter
                    self._window_start = now
                    self._count = 1
                    self._total_calls += 1
                    if now - self._min_start >= 60:
                        self._calls_last_min = 1
                        self._min_start = now
                    else:
                        self._calls_last_min += 1
                    return
                # Priority (hedge) calls can use the full burst including reserved tokens
                effective_burst = self.burst if priority else (self.burst - self.RESERVED_HEDGE_TOKENS)
                if self._count < effective_burst:
                    self._count += 1
                    self._total_calls += 1
                    self._calls_last_min += 1
                    return
                # Burst exhausted — compute sleep, release lock FIRST
                sleep_time = 1.0 - elapsed
            # Sleep OUTSIDE the lock so priority callers aren't blocked
            time.sleep(sleep_time)

    def try_wait(self):
        """Non-blocking: return True if a token was available, False if burst exhausted.
        Use this inside the monitor lock to avoid blocking the entire server."""
        with self._lock:
            now = time.time()
            elapsed = now - self._window_start
            if elapsed >= 1.0:
                self._window_start = now
                self._count = 1
                return True
            effective_burst = self.burst - self.RESERVED_HEDGE_TOKENS
            if self._count < effective_burst:
                self._count += 1
                return True
            return False

api_rate_limiter = RateLimiter(burst=30)  # Kalshi advanced tier: 30 writes/s
api_read_limiter = RateLimiter(burst=30)  # Kalshi advanced tier: 30 reads/s

# ── 429 Rate Limit Tracking (read / write / hedge split) ──
_rate_limit_hits = 0
_rate_limit_reads = 0
_rate_limit_writes = 0
_rate_limit_hedges = 0
_rate_limit_window_start = time.time()
_rate_limit_last_alert = 0
_rate_limit_lock = threading.Lock()

def track_rate_limit_hit(category='unknown'):
    """Call when a 429 is received. category: 'read', 'write', 'hedge', or 'unknown'."""
    global _rate_limit_hits, _rate_limit_reads, _rate_limit_writes, _rate_limit_hedges
    global _rate_limit_window_start, _rate_limit_last_alert
    with _rate_limit_lock:
        now = time.time()
        if now - _rate_limit_window_start >= 60:
            _rate_limit_hits = 0
            _rate_limit_reads = 0
            _rate_limit_writes = 0
            _rate_limit_hedges = 0
            _rate_limit_window_start = now
        _rate_limit_hits += 1
        if category == 'read':
            _rate_limit_reads += 1
        elif category == 'write':
            _rate_limit_writes += 1
        elif category == 'hedge':
            _rate_limit_hedges += 1
            # Hedge 429 is critical — immediate alert
            msg = f'🚨 HEDGE 429: rate limited during hot-path hedge!'
            print(msg)
            bot_log('HEDGE_429', 'system', {'category': category, 'total_hits': _rate_limit_hits})
        # Alert every 10 hits, max once per 30s
        if _rate_limit_hits % 10 == 0 and now - _rate_limit_last_alert >= 30:
            _rate_limit_last_alert = now
            msg = f'⚠ RATE LIMIT: {_rate_limit_hits}/min (R:{_rate_limit_reads} W:{_rate_limit_writes} H:{_rate_limit_hedges})'
            print(msg)

# ─── LocalOrderbook: real-time depth mirror from WS orderbook_delta ───────────
from collections import deque as _deque

class LocalOrderbook:
    """Maintains a real-time mirror of a market's order book from WS deltas.
    Thread-safe: WS thread writes, monitor/signal threads read."""

    def __init__(self, ticker):
        self.ticker = ticker
        self.yes = {}   # {price_cents: qty_float}  — resting YES buy orders
        self.no = {}    # {price_cents: qty_float}  — resting NO buy orders
        self.last_seq = 0
        self.last_update_ts = 0.0
        self._lock = threading.Lock()
        # Rolling depth history for vanishing-liquidity detection (last 20 snapshots)
        self._yes_depth_history = _deque(maxlen=20)
        self._no_depth_history = _deque(maxlen=20)
        # Cached top levels (updated on every delta for fast OBI reads)
        self._yes_top3 = []   # [(price_cents, qty), ...] sorted descending
        self._no_top3 = []

    def seed(self, msg):
        """Initialize from orderbook_snapshot. Replaces entire book."""
        with self._lock:
            self.yes = {}
            for p, q in msg.get('yes_dollars_fp', []):
                cents = int(round(float(p) * 100))
                self.yes[cents] = float(q)
            self.no = {}
            for p, q in msg.get('no_dollars_fp', []):
                cents = int(round(float(p) * 100))
                self.no[cents] = float(q)
            self.last_seq = msg.get('seq', 0)
            self.last_update_ts = time.time()
            self._rebuild_top3()
            self._snapshot_depth()

    def update(self, msg):
        """Apply a single orderbook_delta. Returns True if top-of-book changed."""
        side = msg.get('side', '')
        cents = int(round(float(msg.get('price_dollars', 0)) * 100))
        delta = float(msg.get('delta_fp', 0))
        seq = msg.get('seq', 0)

        with self._lock:
            if seq and seq <= self.last_seq:
                return False  # duplicate/out-of-order
            self.last_seq = seq
            self.last_update_ts = time.time()

            book = self.yes if side == 'yes' else self.no
            old_qty = book.get(cents, 0.0)
            new_qty = old_qty + delta
            if new_qty <= 0:
                book.pop(cents, None)
            else:
                book[cents] = new_qty

            # Check if this delta touches the top 3 levels
            top3 = self._yes_top3 if side == 'yes' else self._no_top3
            top_changed = (not top3 or cents >= top3[-1][0] if len(top3) < 3
                           else cents >= top3[2][0])
            if top_changed:
                self._rebuild_top3()
            return top_changed

    def _rebuild_top3(self):
        """Rebuild cached top-3 bid levels for both sides (highest price = best bid)."""
        self._yes_top3 = sorted(self.yes.items(), key=lambda x: -x[0])[:3]
        self._no_top3 = sorted(self.no.items(), key=lambda x: -x[0])[:3]

    def _snapshot_depth(self):
        """Record current top-level depth for vanishing-liquidity history."""
        now = time.time()
        yes_depth = sum(q for _, q in self._yes_top3)
        no_depth = sum(q for _, q in self._no_top3)
        self._yes_depth_history.append((now, yes_depth))
        self._no_depth_history.append((now, no_depth))

    def get_best_bid(self, side):
        """Get best (highest) bid price in cents for a side. 0 if empty."""
        with self._lock:
            top = self._yes_top3 if side == 'yes' else self._no_top3
            return top[0][0] if top else 0

    def get_best_ask(self, side):
        """Derive the best ask for a side from the opposite side's best bid.
        In Kalshi binary: YES ask = 100 - NO bid, NO ask = 100 - YES bid."""
        opp = 'no' if side == 'yes' else 'yes'
        opp_bid = self.get_best_bid(opp)
        return (100 - opp_bid) if opp_bid > 0 else 0

    def get_depth_at_levels(self, side, n=3):
        """Get top N levels as [(price_cents, qty), ...] sorted best-first."""
        with self._lock:
            top = self._yes_top3 if side == 'yes' else self._no_top3
            return list(top[:n])

    def get_total_depth(self, side, n=3):
        """Sum of quantity across top N levels."""
        return sum(q for _, q in self.get_depth_at_levels(side, n))

    def get_weighted_obi(self, depth=3):
        """Weighted Order Book Imbalance across top N levels.
        Returns -1.0 (NO pressure) to +1.0 (YES pressure). 0 = balanced.
        Weights: [1.0, 0.5, 0.25] — top level matters most."""
        weights = [1.0, 0.5, 0.25]
        with self._lock:
            yes_sum = sum(q * weights[i] for i, (_, q) in enumerate(self._yes_top3[:depth]))
            no_sum = sum(q * weights[i] for i, (_, q) in enumerate(self._no_top3[:depth]))
        total = yes_sum + no_sum
        if total == 0:
            return 0.0
        return (yes_sum - no_sum) / total

    def get_vamp(self, side):
        """Volume-Weighted Average Mid Price for a side.
        VAMP = (BidPrice * AskQty + AskPrice * BidQty) / (BidQty + AskQty)
        More sensitive to 'smart money' depth than simple mid."""
        with self._lock:
            bid_top = self._yes_top3 if side == 'yes' else self._no_top3
            # Ask side = opposite book's best bid inverted
            opp_top = self._no_top3 if side == 'yes' else self._yes_top3
        if not bid_top or not opp_top:
            return 0
        bid_price, bid_qty = bid_top[0]
        ask_price = 100 - opp_top[0][0]  # derive ask from opposite bid
        ask_qty = opp_top[0][1]
        denom = bid_qty + ask_qty
        if denom == 0:
            return (bid_price + ask_price) // 2
        return round((bid_price * ask_qty + ask_price * bid_qty) / denom)

    def detect_vanishing_liquidity(self, side, threshold=0.5, window_s=3.0):
        """GHOST TRIGGER: Returns True if top-3 depth dropped >threshold (50%)
        compared to the average over the last window_s seconds, without a trade.
        Call this after every delta update."""
        now = time.time()
        with self._lock:
            history = self._yes_depth_history if side == 'yes' else self._no_depth_history
            current_depth = sum(q for _, q in (self._yes_top3 if side == 'yes' else self._no_top3))

        if len(history) < 3:
            return False
        # Average depth over the window
        recent = [(ts, d) for ts, d in history if now - ts <= window_s]
        if not recent:
            return False
        avg_depth = sum(d for _, d in recent) / len(recent)
        if avg_depth <= 0:
            return False
        # Did depth drop below threshold of the average?
        return current_depth < avg_depth * (1.0 - threshold)

    def record_depth_snapshot(self):
        """Call periodically (every ~200ms) to build depth history for vanishing-liquidity."""
        with self._lock:
            self._snapshot_depth()

    def get_book_analysis(self, side, window=10, min_qty=10):
        """Analyze book structure for depth rec: gaps, per-level, concentration.
        Levels with qty < min_qty are treated as empty (a whale blows through them).
        Returns dict with gaps, perLevel, top1Qty, totalDepth within window cents of best bid."""
        with self._lock:
            book = dict(self.yes if side == 'yes' else self.no)
        if not book:
            return {'gaps': 0, 'perLevel': 0, 'top1Qty': 0, 'totalDepth': 0, 'concentration': 0}
        sorted_lvls = sorted(book.items(), key=lambda x: -x[0])  # best bid first
        best_bid = sorted_lvls[0][0] if sorted_lvls else 0
        # Only look within window cents of best bid
        all_levels = [(p, q) for p, q in sorted_lvls if best_bid - p < window]
        # Filter out dust levels — too thin to stop a sweep
        levels = [(p, q) for p, q in all_levels if q >= min_qty]
        if not levels:
            return {'gaps': 0, 'perLevel': 0, 'top1Qty': 0,
                    'totalDepth': round(sum(q for _, q in all_levels)),
                    'concentration': 0}
        total = sum(q for _, q in levels)
        top1 = levels[0][1]
        # Count gaps: missing levels AND dust levels between real levels
        gaps = 0
        for i in range(len(levels) - 1):
            gap = levels[i][0] - levels[i + 1][0]
            if gap > 1:
                gaps += gap - 1
        per_level = round(total / max(1, len(levels)))
        conc = top1 / total if total > 0 else 0
        return {'gaps': gaps, 'perLevel': per_level, 'top1Qty': round(top1),
                'totalDepth': round(total), 'concentration': round(conc, 2)}


# Registry of local orderbooks — {ticker: LocalOrderbook}
_local_orderbooks = {}
_local_orderbooks_lock = threading.Lock()

def _get_or_create_orderbook(ticker):
    """Get or create a LocalOrderbook for a ticker."""
    with _local_orderbooks_lock:
        if ticker not in _local_orderbooks:
            _local_orderbooks[ticker] = LocalOrderbook(ticker)
        return _local_orderbooks[ticker]


def _obi_snapshot(bot):
    """Capture OBI + depth at this moment for a phantom bot. Returns dict or None."""
    ticker = bot.get('hedge_ticker', bot.get('ticker', ''))
    dog_side = bot.get('dog_side', 'no')
    fav_side = bot.get('fav_side', 'yes')
    lob = _local_orderbooks.get(ticker) or _local_orderbooks.get(bot.get('ticker', ''))
    if not lob or lob.last_update_ts <= 0:
        return None
    return {
        'obi': round(lob.get_weighted_obi(), 3),
        'dog_depth': round(lob.get_total_depth(dog_side, 3)),
        'fav_depth': round(lob.get_total_depth(fav_side, 3)),
        'dog_best_bid': lob.get_best_bid(dog_side),
        'fav_best_bid': lob.get_best_bid(fav_side),
        'age_ms': round((time.time() - lob.last_update_ts) * 1000),
    }


# ─── WebSocket Manager: real-time price/fill/order monitoring ─────────────────
import websocket as _ws_lib

class KalshiWSManager:
    """
    Manages a single authenticated WebSocket connection to Kalshi.
    Subscribes to orderbook_delta, ticker, fill, and user_orders channels
    for the tickers that active bots care about.

    Keeps a local price cache so the monitor loop can read prices instantly
    instead of making REST calls.
    """

    def __init__(self):
        self._ws = None
        self._thread = None
        self._connected = False
        self._cmd_id = 0
        self._lock = threading.Lock()

        # Local caches updated by WS messages
        self.ticker_cache = {}    # {market_ticker: {yes_bid, yes_ask, no_bid, no_ask, ...}}
        self.fill_events = []     # Recent fill events (capped at 200)
        self.order_events = []    # Recent user_order events (capped at 200)
        self._subscribed_tickers = set()
        self._sids = {}           # {channel: sid}

        # Balance / portfolio cache — updated by WS messages AND a background REST poll
        self.balance_cache = {
            'balance_cents': 0,
            'portfolio_value_cents': 0,
            'positions': {},   # {ticker: {'yes': qty, 'no': qty, 'value_cents': v}}
            'ts': 0,           # last update timestamp
        }
        self._balance_poll_started = False

    @property
    def connected(self):
        return self._connected and self._ws is not None

    def _next_id(self):
        self._cmd_id += 1
        return self._cmd_id

    # ── Connect ──────────────────────────────────────────────────
    def connect(self, kalshi_api):
        """Open WS connection using credentials from the KalshiAPI instance."""
        if self._connected:
            return
        self._api = kalshi_api
        url = kalshi_api.ws_url
        headers = kalshi_api.ws_auth_headers()
        # websocket-client expects header list ["Key: Value", ...]
        header_list = [f'{k}: {v}' for k, v in headers.items()]

        def on_open(ws):
            self._connected = True
            print('🔌 Kalshi WS connected')
            # Subscribe to portfolio channel for live balance/position updates
            threading.Timer(0.5, self._subscribe_portfolio).start()

        def on_message(ws, message):
            try:
                data = json.loads(message)
                self._handle_message(data)
            except Exception as e:
                print(f'⚠ WS message parse error: {e}')

        def on_error(ws, error):
            print(f'⚠ Kalshi WS error: {error}')
            # Mark disconnected so auto-reconnect can fire from on_close
            self._connected = False

        def on_close(ws, close_status_code, close_msg):
            self._connected = False
            self._sids = {}  # Clear stale subscription IDs so re-subscribe sends fresh commands
            # Save tickers before clearing so reconnect can resubscribe
            self._reconnect_tickers = set(self._subscribed_tickers)
            self._subscribed_tickers = set()  # Clear so subscribe() treats them as new
            print(f'🔌 Kalshi WS closed: {close_status_code} {close_msg}')
            # Auto-reconnect after 5 seconds
            threading.Timer(5.0, lambda: self._auto_reconnect(kalshi_api)).start()

        try:
            self._ws = _ws_lib.WebSocketApp(
                url,
                header=header_list,
                on_open=on_open,
                on_message=on_message,
                on_error=on_error,
                on_close=on_close,
            )
            self._thread = threading.Thread(
                target=self._ws.run_forever,
                kwargs={'ping_interval': 10, 'ping_timeout': 5,
                        'ping_payload': 'heartbeat'},
                daemon=True,
            )
            self._thread.start()
        except Exception as e:
            print(f'❌ WS connect failed: {e}')

    def _auto_reconnect(self, kalshi_api):
        """Try to reconnect after a disconnect."""
        if self._connected:
            return
        print('🔄 WS auto-reconnect...')
        try:
            self.connect(kalshi_api)
            # Re-subscribe after reconnect using tickers saved before close cleared them
            time.sleep(1)
            reconnect_tickers = getattr(self, '_reconnect_tickers', set())
            if reconnect_tickers:
                self.subscribe(list(reconnect_tickers))
            threading.Timer(1.0, self._subscribe_portfolio).start()
        except Exception as e:
            print(f'❌ WS reconnect failed: {e}')

    def _subscribe_portfolio(self):
        """No-op: Kalshi WS doesn't support a 'balance' channel (returns error 8).
        Balance updates are handled by start_balance_poll() via REST instead."""
        pass

    def start_balance_poll(self, kalshi_api_client):
        """Start a background thread that polls balance + positions every 15s via REST.
        This serves as fallback when the WS balance channel isn't available."""
        if self._balance_poll_started:
            return  # don't start a second poller
        self._balance_poll_started = True

        def _poller():
            while True:
                try:
                    b = kalshi_api_client.get_balance()
                    self.balance_cache['balance_cents'] = b.get('balance', 0)
                    self.balance_cache['portfolio_value_cents'] = b.get('portfolio_value', 0)
                    # Positions
                    p = kalshi_api_client.get_positions()
                    pos_list = p.get('market_positions', p.get('positions', []))
                    pos_map = {}
                    for pos in pos_list:
                        t = pos.get('ticker', '')
                        qty = _parse_position_qty(pos)
                        val = pos.get('market_exposure', pos.get('value', 0))
                        pos_map[t] = {
                            'yes': max(0, qty),
                            'no':  max(0, -qty),
                            'value_cents': val,
                        }
                    self.balance_cache['positions'] = pos_map
                    self.balance_cache['ts'] = time.time()
                except Exception as _pe:
                    pass  # silent — don't spam logs
                time.sleep(15)
        t = threading.Thread(target=_poller, daemon=True, name='balance-poll')
        t.start()

    def disconnect(self):
        """Close the WS connection."""
        if self._ws:
            try:
                self._ws.close()
            except Exception:
                pass
        self._connected = False
        self._ws = None

    # ── Subscribe / Unsubscribe ────────────────────────────────
    def subscribe(self, tickers):
        """Subscribe to ticker, fill, and user_orders channels for given market tickers."""
        if not self._connected or not self._ws:
            return
        tickers = [t for t in tickers if t]
        if not tickers:
            return
        new_tickers = [t for t in tickers if t not in self._subscribed_tickers]
        if not new_tickers and self._sids:
            return  # Already subscribed

        with self._lock:
            # Market-data channels (need market_tickers)
            for channel in ['ticker', 'orderbook_delta']:
                cmd = {
                    'id': self._next_id(),
                    'cmd': 'subscribe',
                    'params': {
                        'channels': [channel],
                        'market_tickers': new_tickers,
                    }
                }
                self._ws.send(json.dumps(cmd))

            # Private channels — fill and user_orders for these tickers
            for channel in ['fill', 'user_orders']:
                cmd = {
                    'id': self._next_id(),
                    'cmd': 'subscribe',
                    'params': {
                        'channels': [channel],
                        'market_tickers': new_tickers,
                    }
                }
                self._ws.send(json.dumps(cmd))

            self._subscribed_tickers.update(new_tickers)
            print(f'📡 WS subscribed to {len(new_tickers)} tickers: {new_tickers[:5]}...')

    def add_ticker(self, ticker):
        """Add a single ticker to existing subscriptions (or start fresh)."""
        if ticker in self._subscribed_tickers:
            return
        if not self._sids:
            # No existing subs — do a fresh subscribe
            self.subscribe([ticker])
            return
        # Use update_subscription to add to existing sids
        with self._lock:
            for channel, sid in self._sids.items():
                if channel in ('ticker', 'orderbook_delta', 'fill', 'user_orders'):
                    cmd = {
                        'id': self._next_id(),
                        'cmd': 'update_subscription',
                        'params': {
                            'sids': [sid],
                            'market_tickers': [ticker],
                            'action': 'add_markets',
                        }
                    }
                    self._ws.send(json.dumps(cmd))
            self._subscribed_tickers.add(ticker)

    # ── Message handler ──────────────────────────────────────
    def _handle_message(self, data):
        msg_type = data.get('type', '')
        msg = data.get('msg', {})

        if msg_type == 'subscribed':
            channel = msg.get('channel', '')
            sid = data.get('msg', {}).get('sid') or data.get('sid')
            if sid and channel:
                self._sids[channel] = sid
            return

        # ── Orderbook depth mirror (LocalOrderbook) ──
        if msg_type == 'orderbook_snapshot':
            ticker = msg.get('market_ticker', '')
            if ticker:
                ob = _get_or_create_orderbook(ticker)
                ob.seed(msg)
            return

        if msg_type == 'orderbook_delta':
            ticker = msg.get('market_ticker', '')
            if ticker:
                ob = _get_or_create_orderbook(ticker)
                top_changed = ob.update(msg)
                # Record depth snapshot periodically for vanishing-liquidity detection
                if top_changed:
                    ob.record_depth_snapshot()
            return

        if msg_type == 'ticker':
            ticker = msg.get('market_ticker', '')
            if ticker:
                def _ws_cents(field):
                    # Handle new FP format (yes_bid_dollars="0.59") and old int cents (yes_bid=59)
                    d = msg.get(field + '_dollars')
                    if d is not None:
                        return int(round(float(d) * 100))
                    v = msg.get(field, 0)
                    return int(v) if v else 0
                yb = _ws_cents('yes_bid')
                ya = _ws_cents('yes_ask')
                nb = _ws_cents('no_bid')
                na = _ws_cents('no_ask')
                # Market identity: YES ask + NO bid = 100, YES bid + NO ask = 100.
                # Kalshi WS only sends yes_bid / yes_ask — derive the NO side (and fill
                # in any missing ask when only the opposite bid is available).
                if nb == 0 and ya > 0: nb = 100 - ya
                if ya == 0 and nb > 0: ya = 100 - nb
                if na == 0 and yb > 0: na = 100 - yb
                if yb == 0 and na > 0: yb = 100 - na
                self.ticker_cache[ticker] = {
                    'yes_bid': yb,
                    'yes_ask': ya,
                    'no_bid':  nb,
                    'no_ask':  na,
                    'price': msg.get('price', 0),
                    'volume': msg.get('volume', 0),
                    'ts': msg.get('ts', 0),
                    '_local_ts': time.time(),
                }
                # ── Real-time flip threshold check on every WS tick ──
                try:
                    yes_bid_rt = yb
                    no_bid_rt  = nb if nb > 0 else ((100 - ya) if ya > 0 else 0)
                    _ws_realtime_flip_check(ticker, yes_bid_rt, no_bid_rt)
                except Exception as flip_err:
                    print(f'⚠ WS real-time flip check error: {flip_err}')
                # ── Real-time phantom: ALL speed-critical operations on WS ──
                # Background threads — MUST NOT block WS handler (kills hedge latency)
                try:
                    threading.Thread(target=_ws_phantom_instant_drop, args=(ticker, yb, nb, ya, na), daemon=True).start()
                    threading.Thread(target=_ws_phantom_instant_snap_up, args=(ticker, yb, nb, ya, na), daemon=True).start()
                    # ceiling exit system removed — fav snaps to bid with no cap
                    threading.Thread(target=_ws_phantom_price_floor, args=(ticker, yb, nb), daemon=True).start()
                    threading.Thread(target=_ws_phantom_drift_guard, args=(ticker, yb, nb), daemon=True).start()
                except Exception as _pd_err:
                    pass  # don't spam logs on every tick
                # ── Real-time phantom retreat: pull dog if bid approaches order ──
                try:
                    _ws_phantom_retreat(ticker, yb, nb)
                except Exception:
                    pass
                # ── Real-time maker sell follow: amend pending sells on ask change ──
                try:
                    if _pending_maker_sells:
                        threading.Thread(target=_ws_maker_sell_follow, args=(ticker, ya, na), daemon=True).start()
                except Exception:
                    pass
                # ── Real-time Apex MM: stop-loss + snap-down on every tick ──
                try:
                    threading.Thread(target=_ws_apex_mm_tick, args=(ticker, yb, nb, ya, na), daemon=True).start()
                except Exception:
                    pass
            return

        if msg_type == 'fill':
            self.fill_events.insert(0, msg)
            if len(self.fill_events) > 200:
                self.fill_events = self.fill_events[:200]
            ticker = msg.get('market_ticker', '')
            order_id = msg.get('order_id', '')
            side = msg.get('side', '')
            # Kalshi WS may send count_fp (string) or count (int)
            _c = msg.get('count_fp') or msg.get('count') or 0
            count = int(float(_c)) if _c else 0
            print(f'💰 WS FILL: {side} {count}x {ticker} (order {order_id[:8]}...)')
            # ── Real-time fill handling: update bot fill counts + trigger actions ──
            try:
                _ws_realtime_fill_handler(ticker, order_id, side, count)
            except Exception as fh_err:
                print(f'⚠ WS real-time fill handler error: {fh_err}')
            return

        if msg_type == 'user_order':
            self.order_events.insert(0, msg)
            if len(self.order_events) > 200:
                self.order_events = self.order_events[:200]
            return

        if msg_type == 'balance':
            # Kalshi WS balance update — msg contains 'balance' and optionally 'portfolio_value'
            b = msg.get('balance', msg.get('balance_cents'))
            pv = msg.get('portfolio_value', msg.get('portfolio_value_cents'))
            if b is not None:
                self.balance_cache['balance_cents'] = int(b)
            if pv is not None:
                self.balance_cache['portfolio_value_cents'] = int(pv)
            self.balance_cache['ts'] = time.time()
            return

        if msg_type == 'error':
            code = msg.get('code', '?')
            emsg = msg.get('msg', '')
            print(f'⚠ WS error [{code}]: {emsg}')
            return

    # ── Price lookups ───────────────────────────────────────────
    def get_price(self, ticker, max_age_s=60):
        """Get cached price data for a ticker. Returns None if not cached or stale (>max_age_s)."""
        entry = self.ticker_cache.get(ticker)
        if entry and max_age_s > 0:
            cache_age = time.time() - entry.get('_local_ts', 0)
            if cache_age > max_age_s:
                return None  # stale — force REST fallback
        return entry

    def get_fills_for_order(self, order_id):
        """Get all WS fill events for a given order_id."""
        return [f for f in self.fill_events if f.get('order_id') == order_id]

    def get_total_fills(self, order_id):
        """Sum up fill counts for an order_id from WS events."""
        total = 0
        for f in self.fill_events:
            if f.get('order_id') == order_id:
                _c = f.get('count') or f.get('count_fp') or 0
                total += int(float(_c)) if _c else 0
        return total


# Global WS manager instance
ws_manager = KalshiWSManager()

# ─── Monitor lock: prevent concurrent monitor calls from double-executing ─────
monitor_lock = threading.Lock()

# ─── WS Flip lock: prevent WS real-time flip and monitor from double-firing ───
ws_flip_lock = threading.Lock()


def _ws_realtime_flip_check(ticker, yes_bid, no_bid):
    """
    No-op stub — flip logic removed in simultaneous dual-order architecture.
    5/8-minute timeout is handled by the monitor loop instead.
    Kept for signature compatibility.
    """
    return


_phantom_retreat_lock = threading.Lock()

def _ws_phantom_retreat(ticker, yes_bid, no_bid):
    """Real-time retreat: if dog bid drops within 2¢ of our posted price, pull the order.
    Runs synchronously on WS thread — fast check, only cancels if needed."""
    if not _phantom_retreat_lock.acquire(blocking=False):
        return  # another retreat in progress
    try:
        for bot_id, bot in list(active_bots.items()):
            if bot.get('status') != 'dog_anchor_posted':
                continue
            if bot.get('ticker') != ticker:
                continue
            if bot.get('bot_category') != 'anchor_dog':
                continue
            dog_order_id = bot.get('dog_order_id')
            if not dog_order_id:
                continue
            dog_side = bot.get('dog_side', 'no')
            dog_price = bot.get('dog_price', 0)
            dog_bid = yes_bid if dog_side == 'yes' else no_bid
            if dog_bid <= 0 or dog_price <= 0:
                continue
            depth = bot.get('anchor_depth', 5)
            gap = dog_bid - dog_price
            # Retreat when bid is within 2¢ of our order (about to fill at bad price)
            if 0 <= gap <= 2:
                def _retreat_cancel(oid, bid, bot_ref=bot, bot_id_ref=bot_id):
                    result = _safe_cancel(oid, f'ws_retreat_{bid}')
                    # _safe_cancel returns ('filled', count) when 404 with fills
                    # Only recover if WS fill handler hasn't already fired the hedge
                    _fills = 0
                    if isinstance(result, tuple) and result[0] == 'filled':
                        _fills = result[1]
                    elif result == '404' or result is None:
                        try:
                            api_read_limiter.wait()
                            _ord = kalshi_client.get_order(oid)
                            _od = _ord.get('order', _ord) if isinstance(_ord, dict) else {}
                            _fills = _parse_fill_count(_od)
                        except Exception as _e:
                            print(f'⚠ WS RETREAT FILL CHECK FAILED: {bot_id_ref}: {_e}')
                    if _fills > 0 and not bot_ref.get('_hedge_fired'):
                        print(f'🚨 WS RETREAT FILL DETECTED: {bot_id_ref} order {oid[:12]} had {_fills} fills!')
                        bot_log('WS_RETREAT_FILL_ON_404', bot_id_ref, {
                            'order_id': oid, 'fills': _fills, 'dog_price': bot_ref.get('dog_price'),
                        }, level='ERROR')
                        bot_ref['dog_fill_qty'] = max(bot_ref.get('dog_fill_qty', 0), _fills)
                        _ds = bot_ref.get('dog_side', 'no')
                        bot_ref[f'{_ds}_fill_qty'] = bot_ref['dog_fill_qty']
                        bot_ref['status'] = 'dog_filled'
                        bot_ref['dog_filled_at'] = time.time()
                        bot_ref['_hedge_fired'] = True
                        _qty = bot_ref.get('quantity', 1)
                        if _fills < _qty:
                            bot_ref['_original_qty'] = _qty
                            bot_ref['_partial_hedge_qty'] = _fills
                        _hedge_worker_queue.put((_execute_phantom_hedge, (bot_id_ref,)))
                        print(f'⚡ WS RETREAT → INSTANT HEDGE: {bot_id_ref} {_fills}x fills — hedge fired')
                        save_state()
                threading.Thread(target=_retreat_cancel, args=(dog_order_id, bot_id), daemon=True).start()
                bot['dog_order_id'] = None
                bot['_last_retreat_at'] = time.time()
                bot['status'] = 'waiting_repeat'
                bot['waiting_repeat_since'] = time.time() + 1
                print(f'⚡ WS RETREAT: {bot_id} bid={dog_bid}¢ gap={gap}¢ from dog@{dog_price}¢ — pulled instantly')
                bot_log('PHANTOM_WS_RETREAT', bot_id, {
                    'dog_bid': dog_bid, 'dog_price': dog_price, 'gap': gap, 'depth': depth,
                })
                save_state()
    finally:
        _phantom_retreat_lock.release()


_maker_sell_follow_lock = threading.Lock()

def _ws_maker_sell_follow(ticker, yes_ask, no_ask):
    """WS-driven: instantly amend pending maker sells when ask drops below posted price."""
    if not _pending_maker_sells:
        return
    if not _maker_sell_follow_lock.acquire(blocking=False):
        return
    try:
        for _sk, _sv in list(_pending_maker_sells.items()):
            if _sv.get('ticker') != ticker:
                continue
            _side = _sv.get('side', '')
            _current_ask = yes_ask if _side == 'yes' else no_ask
            if _current_ask <= 0:
                continue
            _posted = _sv.get('posted_price', 0)
            if _current_ask >= _posted:
                continue  # ask hasn't dropped, we're already competitive
            # Ask dropped below us — amend down instantly
            try:
                _amend_kw = {f'{_side}_price': _current_ask}
                api_rate_limiter.wait()
                _sell_resp = kalshi_client.amend_order(_sv['oid'], ticker=ticker, side=_side,
                                         count=_sv.get('qty', 1), **_amend_kw)
                # Kalshi amend can return a new order ID — track it
                _sell_ord = _sell_resp.get('order', _sell_resp) if isinstance(_sell_resp, dict) else {}
                _sell_new_oid = _sell_ord.get('order_id', '')
                if _sell_new_oid and _sell_new_oid != _sv['oid']:
                    _sv['oid'] = _sell_new_oid
                _sv['posted_price'] = _current_ask
                print(f'⚡ WS MAKER SELL SNAP: {_sv["reason"]} {_side} {ticker} → {_current_ask}¢')
            except Exception as _e:
                if '404' in str(_e) or 'not found' in str(_e).lower():
                    print(f'⚠ WS MAKER SELL SNAP: order gone for {_sv["reason"]} — will repost on next monitor tick')
    finally:
        _maker_sell_follow_lock.release()


# Lock to prevent concurrent phantom drop amends
_phantom_drop_lock = threading.Lock()

def _ws_phantom_instant_drop(ticker, yes_bid, no_bid, yes_ask, no_ask):
    """Instant drop: if any phantom bot's hedge is above the fav bid, amend down immediately.
    Called on every WS price tick — must be fast. Only acts when price > bid (overpaying)."""
    for bot_id, bot in list(active_bots.items()):
        if bot.get('bot_category') != 'anchor_dog':
            continue
        if bot.get('status') != 'fav_hedge_posted':
            continue
        # Match ticker (same-market or cross-market hedge)
        hedge_ticker = bot.get('hedge_ticker', bot.get('ticker', ''))
        if hedge_ticker != ticker and bot.get('ticker') != ticker:
            continue

        fav_side = bot.get('fav_side', '')
        fav_price = bot.get('fav_price') or 0
        if fav_price <= 0 or not fav_side:
            continue

        # Get current bid for fav side from this WS tick
        fav_bid = (yes_bid if fav_side == 'yes' else no_bid) if hedge_ticker == ticker else 0
        if fav_bid <= 0:
            continue

        # Only drop if hedge is ABOVE bid (overpaying)
        if fav_price <= fav_bid:
            continue

        # Drop to bid — same as monitor snap, no bid+1 (phantom always posts at bid)
        fav_ask_now = yes_ask if fav_side == 'yes' else no_ask
        drop_target = fav_bid

        if drop_target <= 0 or drop_target >= fav_price:
            continue

        # Acquire lock — only one amend at a time (prevents race with monitor walk)
        if not _phantom_drop_lock.acquire(blocking=False):
            return  # another drop or walk in progress

        try:
            # Re-read fav_order_id AFTER acquiring lock (monitor may have updated it)
            fav_oid = bot.get('fav_order_id')
            if not fav_oid:
                continue
            amend_kwargs = {f'{fav_side}_price': drop_target}
            api_rate_limiter.wait()
            _amend_resp = kalshi_client.amend_order(fav_oid, ticker=hedge_ticker, side=fav_side,
                                      count=bot.get('_partial_hedge_qty') or bot.get('hedge_qty', bot.get('quantity', 1)),
                                      **amend_kwargs)
            # Capture new order ID if Kalshi reassigned (amend = cancel+repost internally)
            _amend_order = _amend_resp.get('order', _amend_resp) if isinstance(_amend_resp, dict) else {}
            _new_oid = _amend_order.get('order_id', '')
            if _new_oid and _new_oid != fav_oid:
                bot['fav_order_id'] = _new_oid
                if fav_side == 'yes':
                    bot['yes_order_id'] = _new_oid
                else:
                    bot['no_order_id'] = _new_oid
            bot['fav_price'] = drop_target
            if fav_side == 'yes':
                bot['yes_price'] = drop_target
            else:
                bot['no_price'] = drop_target
            bot['fav_last_walk_at'] = time.time()
            bot['fav_walk_count'] = bot.get('fav_walk_count', 0) + 1
            print(f'⚡ WS PHANTOM DROP: {bot_id} fav {fav_price}→{drop_target}¢ (bid={fav_bid}¢)')
            bot_log('PHANTOM_WS_INSTANT_DROP', bot_id, {
                'old_price': fav_price, 'new_price': drop_target,
                'fav_bid': fav_bid, 'fav_ask': fav_ask_now,
            })
            save_state()
        except Exception as e:
            if '404' not in str(e):
                print(f'⚠ WS PHANTOM DROP FAIL: {bot_id}: {e}')
        finally:
            _phantom_drop_lock.release()
        return  # one drop per tick max


    # Ceiling exit system removed — fav snaps to bid with no cap, fills complete arb at any combined price


def _ws_phantom_price_floor(ticker, yes_bid, no_bid):
    """Instant price floor: pull dog order if bid drops below 2¢."""
    for bot_id, bot in list(active_bots.items()):
        if bot.get('bot_category') != 'anchor_dog':
            continue
        if bot.get('status') != 'dog_anchor_posted':
            continue
        if bot.get('ticker') != ticker:
            continue
        if bot.get('_price_floor_pulled'):
            continue

        dog_side = bot.get('dog_side', '')
        dog_bid = (yes_bid if dog_side == 'yes' else no_bid)
        if dog_bid <= 0 or dog_bid >= 2:
            continue

        dog_oid = bot.get('dog_order_id')
        if not dog_oid:
            continue

        _safe_cancel(dog_oid, f'ws_price_floor_{bot_id}')
        bot['dog_order_id'] = None
        bot['_price_floor_pulled'] = True
        bot['_price_floor_at'] = time.time()
        print(f'⚡ WS PRICE FLOOR: {bot_id} bid={dog_bid}¢ < 2¢ — pulled instantly')
        bot_log('PHANTOM_WS_PRICE_FLOOR', bot_id, {
            'dog_bid': dog_bid, 'dog_side': dog_side,
        })
        save_state()
        return


def _ws_phantom_drift_guard(ticker, yes_bid, no_bid):
    """Instant drift guard: cancel dog if bid crosses 50¢ (sides flipped)."""
    for bot_id, bot in list(active_bots.items()):
        if bot.get('bot_category') != 'anchor_dog':
            continue
        if bot.get('status') != 'dog_anchor_posted':
            continue
        if bot.get('ticker') != ticker:
            continue

        dog_side = bot.get('dog_side', '')
        dog_bid = (yes_bid if dog_side == 'yes' else no_bid)
        if dog_bid <= 50:
            continue

        dog_oid = bot.get('dog_order_id')
        if not dog_oid:
            continue

        # Same-market: flip sides instead of killing
        _is_cross = bot.get('hedge_ticker') and bot.get('hedge_ticker') != ticker
        if not _is_cross:
            _opp = 'yes' if dog_side == 'no' else 'no'
            _opp_bid = (yes_bid if _opp == 'yes' else no_bid)
            if _opp_bid > 0 and _opp_bid < dog_bid:
                _safe_cancel(dog_oid, f'ws_drift_flip_{bot_id}')
                bot['dog_side'] = _opp
                bot['fav_side'] = dog_side
                bot['dog_order_id'] = None
                bot['dog_fill_qty'] = 0
                bot['fav_fill_qty'] = 0
                bot['_hedge_fired'] = False
                bot['_trade_recorded'] = False
                bot['_all_dog_order_ids'] = []
                bot['_flip_pending'] = True
                bot['status'] = 'waiting_repeat'
                bot['waiting_repeat_since'] = time.time()
                print(f'⚡ WS DRIFT FLIP: {bot_id} {dog_side}@{dog_bid}¢→fav, {_opp}@{_opp_bid}¢→dog')
                bot_log('PHANTOM_WS_DRIFT_FLIP', bot_id, {
                    'old_dog': dog_side, 'dog_bid': dog_bid,
                    'new_dog': _opp, 'opp_bid': _opp_bid,
                })
                save_state()
                return
        # Cross-market or can't flip — pull and wait for recovery
        _safe_cancel(dog_oid, f'ws_drift_pull_{bot_id}')
        bot['dog_order_id'] = None
        bot['_price_floor_pulled'] = True
        bot['_price_floor_since'] = time.time()
        print(f'⚡ WS DRIFT PULL: {bot_id} bid={dog_bid}¢ > 50¢ — pulled, waiting')
        bot_log('PHANTOM_WS_DRIFT_PULL', bot_id, {'dog_bid': dog_bid})
        save_state()
        return


    # Ceiling sell follow removed — no more dog sell system


def _phantom_taker_depth_tier(fav_depth):
    """Thin book = taker sooner (nobody lifting maker). Thick book = more patient (fills likely).
    Returns timer_seconds only — no threshold. Once timer expires, cross the spread unconditionally."""
    if fav_depth < 200:    return 10    # THIN: nobody taking, cross fast
    elif fav_depth < 500:  return 15    # MODERATE: give maker a fair shot
    else:                  return 30    # THICK: plenty of takers, be patient


def _ws_phantom_instant_snap_up(ticker, yes_bid, no_bid, yes_ask, no_ask):
    """Instant snap UP: if fav bid rose above posted price, amend up immediately.
    Catches fast market moves (tennis breaks, game events) before the 2s monitor cycle.
    Called on every WS price tick — runs in background thread."""
    for bot_id, bot in list(active_bots.items()):
        if bot.get('bot_category') != 'anchor_dog':
            continue
        if bot.get('status') != 'fav_hedge_posted':
            continue
        hedge_ticker = bot.get('hedge_ticker', bot.get('ticker', ''))
        if hedge_ticker != ticker and bot.get('ticker') != ticker:
            continue

        fav_side = bot.get('fav_side', '')
        fav_price = bot.get('fav_price') or 0
        if fav_price <= 0 or not fav_side:
            continue

        fav_bid = (yes_bid if fav_side == 'yes' else no_bid) if hedge_ticker == ticker else 0
        if fav_bid <= 0:
            continue

        # ── Depth-aware taker fallback: thin books fire sooner, thick books stay patient ──
        fav_ask = (yes_ask if fav_side == 'yes' else no_ask) if hedge_ticker == ticker else 0
        dog_price = bot.get('dog_price', 0)
        posted_at = bot.get('fav_posted_at', bot.get('dog_filled_at', 0))
        hedge_age = time.time() - posted_at if posted_at > 0 else 0

        # Read real-time fav depth at bid level (1 level = what the card shows)
        _lob = _local_orderbooks.get(hedge_ticker)
        _fav_depth = round(_lob.get_total_depth(fav_side, 1)) if _lob and _lob.last_update_ts > 0 else 0
        _taker_timer = _phantom_taker_depth_tier(_fav_depth)

        # ── Timer expired: jump to bid+1 (aggressive maker, not taker) ──
        # If bid+1 == ask, this crosses the spread (taker). If spread > 1c, you're
        # first in queue at bid+1 — better position without paying spread cost.
        if fav_bid > 0 and hedge_age >= _taker_timer and not bot.get('_taker_fired'):
            _target = fav_bid + 1
            if _target > fav_price:  # only if bid+1 is above current posted price
                if not _phantom_drop_lock.acquire(blocking=False):
                    return
                try:
                    fav_oid = bot.get('fav_order_id')
                    if fav_oid:
                        qty = bot.get('_partial_hedge_qty') or bot.get('hedge_qty', bot.get('quantity', 1))
                        amend_kwargs = {f'{fav_side}_price': _target}
                        api_rate_limiter.wait(priority=True)
                        kalshi_client.amend_order(fav_oid, ticker=hedge_ticker, side=fav_side,
                                                  count=qty, **amend_kwargs)
                        _is_taker = fav_ask > 0 and _target >= fav_ask
                        bot['fav_price'] = _target
                        bot['_taker_fired'] = True
                        bot['_fav_was_taker'] = _is_taker
                        _depth_label = 'THIN' if _fav_depth < 200 else ('MOD' if _fav_depth < 500 else 'THICK')
                        _mode = 'TAKER (bid+1=ask)' if _is_taker else f'BID+1 (ask={fav_ask}¢)'
                        combined = dog_price + _target
                        print(f'⚡ WS PHANTOM {_mode}: {bot_id} fav→{_target}¢ (combined={combined}¢, waited {int(hedge_age)}s, depth={_fav_depth} [{_depth_label}])')
                        bot_log('PHANTOM_WS_TAKER', bot_id, {
                            'fav_price': _target, 'dog_price': dog_price,
                            'combined': combined, 'hedge_age_s': int(hedge_age),
                            'was_price': fav_price, 'fav_ask': fav_ask,
                            'is_taker': _is_taker, 'fav_bid': fav_bid,
                            'fav_depth': _fav_depth, 'depth_tier': _depth_label,
                            'taker_timer': _taker_timer,
                        })
                        save_state()
                finally:
                    _phantom_drop_lock.release()
                return

        # Only snap if bid is ABOVE posted price (we're behind the market)
        if fav_bid <= fav_price:
            continue

        # No ceiling cap — snap to bid regardless of combined price
        snap_target = fav_bid

        # Acquire lock — prevents race with monitor walk and instant drop
        if not _phantom_drop_lock.acquire(blocking=False):
            return

        try:
            fav_oid = bot.get('fav_order_id')
            if not fav_oid:
                continue
            qty = bot.get('_partial_hedge_qty') or bot.get('hedge_qty', bot.get('quantity', 1))
            amend_kwargs = {f'{fav_side}_price': snap_target}
            api_rate_limiter.wait()
            _amend_resp = kalshi_client.amend_order(fav_oid, ticker=hedge_ticker, side=fav_side,
                                        count=qty, **amend_kwargs)
            _amend_order = _amend_resp.get('order', _amend_resp) if isinstance(_amend_resp, dict) else {}
            _new_oid = _amend_order.get('order_id', '')
            if _new_oid and _new_oid != fav_oid:
                bot['fav_order_id'] = _new_oid
                bot.setdefault('_all_hedge_order_ids', []).append(fav_oid)
                if fav_side == 'yes':
                    bot['yes_order_id'] = _new_oid
                else:
                    bot['no_order_id'] = _new_oid
            bot['fav_price'] = snap_target
            if fav_side == 'yes':
                bot['yes_price'] = snap_target
            else:
                bot['no_price'] = snap_target
            bot['fav_last_walk_at'] = time.time()
            bot['fav_walk_count'] = bot.get('fav_walk_count', 0) + 1
            _snap_dog_price = bot.get('dog_price', 0)
            combined = _snap_dog_price + snap_target
            print(f'⚡ WS PHANTOM SNAP UP: {bot_id} fav {fav_price}→{snap_target}¢ (bid={fav_bid}¢ combined={combined}¢)')
            bot_log('PHANTOM_WS_INSTANT_SNAP_UP', bot_id, {
                'old_price': fav_price, 'new_price': snap_target,
                'fav_bid': fav_bid, 'dog_price': _snap_dog_price,
                'combined': combined,
            })
            save_state()
        except Exception as e:
            if '404' not in str(e):
                print(f'⚠ WS PHANTOM SNAP UP FAIL: {bot_id}: {e}')
        finally:
            _phantom_drop_lock.release()
        return  # one snap per tick max


def _execute_ws_flip(bot_id, filled_side, entry_price, trigger_bid, flip_thresh, filled_qty, floor=None):
    """
    No-op stub — flip logic removed in simultaneous dual-order architecture.
    5/8-minute timeout is handled by the monitor loop instead.
    Kept for signature compatibility.
    """
    pass


# ─── WS Apex MM: stop-loss + snap-down on every tick ─────────────────────────
_ws_apex_mm_tick_lock = threading.Lock()

def _ws_apex_mm_tick(ticker, yes_bid, no_bid, yes_ask, no_ask):
    """WS-tick handler for Apex MM. Fires on every price tick. Three jobs:
    Priority 0: Shadow exit — instant amend of mm_exiting sell/buy orders to track bid/ask.
    Priority 1: Stop-loss — if combined >= 100+width, emergency exit immediately.
    Priority 2: Snap-down — if exit bid dropped below posted price, amend down for better fill."""
    if not _ws_apex_mm_tick_lock.acquire(blocking=False):
        return  # another check in progress — skip
    try:
        for bot_id, bot in list(active_bots.items()):
            if bot.get('bot_category') != 'ladder_arb':
                continue
            if bot.get('type') != 'apex_mm':
                continue
            status = bot.get('status', '')
            if status not in ('market_making_active', 'mm_exiting'):
                continue
            if bot.get('ticker') != ticker:
                continue

            # ── Priority 0: Shadow exit orders (mm_exiting) ──
            if status == 'mm_exiting':
                for _sh_side, _sh_info in list(bot.get('_exit_sell_oids', {}).items()):
                    _sh_oid = _sh_info.get('oid')
                    if not _sh_oid:
                        continue
                    _sh_action = _sh_info.get('action', 'sell')
                    _sh_current = _sh_info.get('price', 0)
                    _sh_qty = _sh_info.get('qty', 0)
                    if _sh_current <= 0 or _sh_qty <= 0:
                        continue

                    if _sh_action == 'buy':
                        # Buy opposite: shadow the bid (buy at front of bid queue)
                        _sh_live = yes_bid if _sh_side == 'yes' else no_bid
                    else:
                        # Sell held: shadow the ask (sell at front of ask queue)
                        _sh_opp = 'no' if _sh_side == 'yes' else 'yes'
                        _sh_opp_bid = yes_bid if _sh_opp == 'yes' else no_bid
                        _sh_live = (100 - _sh_opp_bid) if _sh_opp_bid > 0 else 0

                    if _sh_live <= 0 or _sh_live == _sh_current:
                        continue  # no change

                    try:
                        _sh_price_kwarg = {f'{_sh_side}_price': _sh_live}
                        api_rate_limiter.wait()
                        kalshi_client.amend_order(_sh_oid, ticker=ticker, side=_sh_side,
                                                  count=_sh_qty, action=_sh_action, **_sh_price_kwarg)
                        _sh_info['price'] = _sh_live
                        _sh_info['posted_at'] = time.time()
                        print(f'👤 APEX MM SHADOW: {bot_id} {_sh_action} {_sh_side.upper()} {_sh_current}→{_sh_live}c')
                    except Exception as _sh_e:
                        _sh_err = str(_sh_e)
                        if '404' not in _sh_err and 'filled' not in _sh_err.lower():
                            print(f'⚠ APEX MM SHADOW FAIL: {bot_id} {_sh_side}: {_sh_e}')
                continue  # mm_exiting bots skip stop-loss/snap-down

            # ── market_making_active from here ──
            net_yes = bot.get('net_yes', 0)
            net_no = bot.get('net_no', 0)
            if net_yes <= 0 and net_no <= 0:
                # Flat — clear stale breach timer (both sides may have filled during gate)
                bot['_sl_breach_since'] = None
                bot['_sl_breach_peak'] = None
                bot['_sl_breach_phase'] = None
                continue

            if net_yes > net_no:
                held_avg = bot.get('avg_yes_cost', 0)
                exit_side = 'no'
                held_side = 'yes'
            else:
                held_avg = bot.get('avg_no_cost', 0)
                exit_side = 'yes'
                held_side = 'no'

            # ── Priority 1: Stop-loss ──
            exit_ask = yes_ask if exit_side == 'yes' else no_ask
            held_bid = yes_bid if held_side == 'yes' else no_bid
            buy_opp = (held_avg + exit_ask) if exit_ask > 0 else 999
            sell_held = (held_avg + (100 - held_bid)) if held_bid > 0 else 999
            best_combined = min(buy_opp, sell_held)

            width = bot.get('start_gap', 4) * 2
            stop = 100 + width

            if best_combined >= stop and best_combined < 999:
                hard_stop = stop + APEX_MM_SL_HARD_MARGIN
                _pc = time.perf_counter()  # monotonic, nanosecond res — immune to NTP drift

                # ── HARD BREACH: circuit breaker — instant eject, no timer ──
                if best_combined > hard_stop:
                    bot['status'] = 'mm_exiting'
                    _breach_dur = _pc - bot['_sl_breach_since'] if bot.get('_sl_breach_since') else 0
                    print(f'🚨 APEX MM CIRCUIT BREAKER: {bot_id} combined={best_combined}c > {hard_stop}c — INSTANT EJECT (binary gap, breach_dur={_breach_dur:.3f}s)')
                    def _fire_exit(_bid=bot_id, _b=bot, _bc=best_combined, _hs=hard_stop, _w=width):
                        _apex_mm_begin_exit(_bid, _b, f'circuit_breaker (combined={_bc}c > {_hs}c, hard_margin={APEX_MM_SL_HARD_MARGIN}c)')
                    threading.Thread(target=_fire_exit, daemon=True).start()
                    return

                # ── SOFT BREACH: persistence gate — filter flash spikes ──
                _persist_s, _phase = _apex_mm_sl_persist(ticker)
                if not bot.get('_sl_breach_since'):
                    bot['_sl_breach_since'] = _pc
                    bot['_sl_breach_peak'] = best_combined
                    bot['_sl_breach_phase'] = _phase
                    print(f'⏱ APEX MM SOFT BREACH: {bot_id} combined={best_combined}c >= {stop}c — gate {_persist_s}s ({_phase})')
                    continue
                bot['_sl_breach_peak'] = max(bot.get('_sl_breach_peak', 0), best_combined)
                _breach_age = _pc - bot['_sl_breach_since']
                if _breach_age < _persist_s:
                    continue  # still within persistence window — let it breathe
                # Persisted long enough — fire the exit
                bot['status'] = 'mm_exiting'
                print(f'🚨 APEX MM WS STOP-LOSS: {bot_id} combined={best_combined}c >= {stop}c — persisted {_breach_age:.3f}s/{_persist_s}s ({_phase}, peak={bot.get("_sl_breach_peak", 0)}c)')
                def _fire_exit(_bid=bot_id, _b=bot, _bc=best_combined, _s=stop, _w=width, _age=_breach_age, _ph=_phase):
                    _apex_mm_begin_exit(_bid, _b, f'ws_stop_loss (combined={_bc}c >= {_s}c, persisted={_age:.3f}s, phase={_ph})')
                threading.Thread(target=_fire_exit, daemon=True).start()
                return
            else:
                # Combined back below stop — reset persistence gate instantly
                if bot.get('_sl_breach_since'):
                    _breach_dur = time.perf_counter() - bot['_sl_breach_since']
                    print(f'✅ APEX MM SL RESET: {bot_id} combined={best_combined}c < {stop}c — filtered {_breach_dur:.3f}s spike (peak={bot.get("_sl_breach_peak", 0)}c, phase={bot.get("_sl_breach_phase", "?")})')
                    bot['_sl_breach_since'] = None
                    bot['_sl_breach_peak'] = None
                    bot['_sl_breach_phase'] = None

            # ── Priority 2: Snap-down — chase cheaper exit price ──
            exit_oid = bot.get(f'_{exit_side}_exit_oid')
            if not exit_oid:
                continue
            current_price = bot.get('_exit_price', 0)
            if current_price <= 0:
                continue
            exit_bid = yes_bid if exit_side == 'yes' else no_bid
            if exit_bid <= 0 or exit_bid >= current_price - 1:
                continue  # bid not below current — nothing to snap to

            snap_price = max(1, exit_bid)
            target_price = bot.get('_exit_target_price', 0)
            net_held = abs(net_yes - net_no)
            try:
                price_kwarg = {f'{exit_side}_price': snap_price}
                api_rate_limiter.wait()
                kalshi_client.amend_order(exit_oid, ticker=ticker, side=exit_side,
                                          count=net_held, action='buy', **price_kwarg)
                bot['_exit_price'] = snap_price
                bot['_wall_parked'] = False
                if snap_price <= target_price:
                    bot['_exit_soak_start'] = time.time()
                    bot['_exit_walk_count'] = 0
                combined = held_avg + snap_price
                print(f'📊 APEX MM WS SNAP-DOWN: {bot_id} {exit_side.upper()} {current_price}→{snap_price}c (combined={combined}c, bid={exit_bid})')
                bot_log('APEX_MM_WS_SNAP_DOWN', bot_id, {
                    'old': current_price, 'new': snap_price, 'bid': exit_bid,
                    'combined': combined, 'target': target_price,
                })
            except Exception as e:
                if '404' not in str(e) and 'filled' not in str(e).lower():
                    print(f'⚠ APEX MM WS SNAP-DOWN FAIL: {bot_id}: {e}')
    finally:
        _ws_apex_mm_tick_lock.release()


# ─── WS Fill Lock: prevent WS fill handler and monitor from double-acting ─────
ws_fill_lock = threading.RLock()
# ─── Apex MM Amend Exit Lock: prevent concurrent threads from creating duplicate exit orders ───
_apex_mm_amend_exit_lock = threading.Lock()
# ─── Late Anchor Amend Lock: serialize late anchor amend API calls ────────────
# ─── Phantom Hedge Worker: pre-spawned thread for instant hedge placement ─────
# Eliminates ~8ms thread spawn overhead. WS handler pushes jobs, worker executes
# instantly. The #1 speed priority in the entire app.
import queue as _queue_mod
_hedge_worker_queue = _queue_mod.Queue()
_HEDGE_WORKER_COUNT = 4  # parallel hedges — no bot waits on another's API call

def _hedge_worker_loop():
    """Pre-warmed worker thread — blocks on queue.get(), fires instantly on fill."""
    while True:
        try:
            job = _hedge_worker_queue.get()
            if job is None:
                break
            fn, args = job
            fn(*args)
        except Exception as e:
            print(f'⚠ HEDGE WORKER ERROR: {e}')

for _i in range(_HEDGE_WORKER_COUNT):
    threading.Thread(target=_hedge_worker_loop, daemon=True, name=f'hedge-worker-{_i}').start()

# ─── Pending WS actions: queued by WS handler, drained by monitor into response ─
# This ensures the frontend sees 'completed' / 'timeout_exit' actions even when
# the WS handler wins the race against the REST monitor loop.
_pending_ws_actions = []
_pending_ws_actions_lock = threading.Lock()


def _ws_realtime_fill_handler(ticker, order_id, side, count):
    """
    Real-time fill handler triggered directly from the WebSocket fill event.
    Matches the fill to an active bot and:
      1. Updates fill counts immediately
      2. If fav leg just completed → posts dog leg instantly
      3. If both legs now filled → marks completed instantly

    Actions are dispatched to background threads so the WS handler doesn't block.
    """
    if not active_bots or not kalshi_client:
        return

    for bot_id, bot in list(active_bots.items()):
        if bot.get('ticker') != ticker:
            continue
        if bot.get('type') == 'watch':
            continue
        # Skip phantom bots — handled by dedicated anchor-dog section below
        if bot.get('bot_category') == 'anchor_dog':
            continue
        status = bot.get('status', '')
        if status in ('stopped', 'completed'):
            continue

        # Match fill to this bot's order IDs
        matched_leg = None  # 'yes' or 'no'
        if order_id == bot.get('yes_order_id') or (order_id == bot.get('fav_order_id') and bot.get('fav_side') == 'yes'):
            matched_leg = 'yes'
        elif order_id == bot.get('no_order_id') or (order_id == bot.get('fav_order_id') and bot.get('fav_side') == 'no'):
            matched_leg = 'no'

        if not matched_leg:
            continue

        qty = bot['quantity']

        # Update fill counts — accumulate (WS sends incremental fills)
        if matched_leg == 'yes':
            bot['yes_fill_qty'] = bot.get('yes_fill_qty', 0) + count
            yes_filled = bot['yes_fill_qty']
            no_filled = bot.get('no_fill_qty', 0)
        else:
            bot['no_fill_qty'] = bot.get('no_fill_qty', 0) + count
            no_filled = bot['no_fill_qty']
            yes_filled = bot.get('yes_fill_qty', 0)

        print(f'⚡ WS FILL UPDATE: {bot_id} {matched_leg.upper()} +{count} '
              f'→ YES={yes_filled}/{qty} NO={no_filled}/{qty}')

        # ── Both legs fully filled → instant completion ──
        if yes_filled >= qty and no_filled >= qty:
            if bot.get('_ws_fill_handling'):
                continue
            bot['_ws_fill_handling'] = True
            print(f'⚡ WS INSTANT COMPLETE: {bot_id} — both legs filled!')
            threading.Thread(
                target=_execute_ws_completion,
                args=(bot_id,),
                daemon=True
            ).start()
            break

        # ── Fav leg just completed → instant dog-leg posting ──
        if status == 'fav_posted':
            fav_side = bot.get('fav_side', 'yes')
            fav_filled = yes_filled if fav_side == 'yes' else no_filled
            if fav_filled >= qty:
                if bot.get('_ws_fill_handling'):
                    continue
                bot['_ws_fill_handling'] = True
                print(f'⚡ WS INSTANT FAV FILL: {bot_id} {fav_side.upper()} filled — posting dog leg NOW')
                threading.Thread(
                    target=_execute_ws_dog_post,
                    args=(bot_id,),
                    daemon=True
                ).start()
                break

        break  # Only one bot can match this order_id (arb bot)

    # ── Middle Bot WS fill matching (keyed by order_a_id / order_b_id, no ticker filter) ──
    for bot_id, bot in list(active_bots.items()):
        if bot.get('type') != 'middle':
            continue
        if bot.get('status') in ('stopped', 'completed', 'both_filled'):
            continue
        matched_leg = None
        if order_id == bot.get('order_a_id'):
            matched_leg = 'a'
        elif order_id == bot.get('order_b_id'):
            matched_leg = 'b'
        if not matched_leg:
            continue

        qty = bot.get('qty', 1)
        fill_key = f'leg_{matched_leg}_fill_qty'
        bot[fill_key] = bot.get(fill_key, 0) + count
        fill_qty = bot[fill_key]
        print(f'⚡ WS MIDDLE FILL: {bot_id} LEG {matched_leg.upper()} +{count} → {fill_qty}/{qty}')

        if fill_qty >= qty:
            fill_price = bot.get(f'target_price_{matched_leg}', bot.get('target_price', 49))
            bot[f'leg_{matched_leg}_filled'] = True
            bot[f'leg_{matched_leg}_fill_price'] = fill_price
            other_leg = 'b' if matched_leg == 'a' else 'a'
            other_filled = bot.get(f'leg_{other_leg}_filled', False)
            if other_filled:
                bot['status'] = 'both_filled'
                bot['both_filled_at'] = time.time()
                bot_log('MIDDLE_BOTH_FILLED', bot_id, {'leg': matched_leg, 'source': 'ws_realtime'})
                print(f'⚡ WS MIDDLE BOTH FILLED: {bot_id}')
            else:
                bot['status'] = 'one_filled'
                bot['filled_leg'] = matched_leg
                bot['one_filled_at'] = time.time()
                bot_log('MIDDLE_LEG_FILLED', bot_id, {'leg': matched_leg, 'source': 'ws_realtime'})
                print(f'⚡ WS MIDDLE LEG {matched_leg.upper()} FILLED: {bot_id}')
            save_state()
        break

    # ── Anchor-Dog WS fill matching ──────────────────────────────
    for bot_id, bot in list(active_bots.items()):
        if bot.get('bot_category') != 'anchor_dog':
            continue
        if bot.get('status') not in ('dog_anchor_posted', 'fav_hedge_posted'):
            continue
        matched = None
        if order_id == bot.get('dog_order_id') and bot['status'] == 'dog_anchor_posted':
            matched = 'dog'
        elif order_id in set(bot.get('_all_dog_order_ids') or []) and bot['status'] == 'dog_anchor_posted':
            # Cancel-race: old order MIGHT have filled after repost — verify before acting
            # Stale WS events for cancelled orders cause ghost fills if not verified
            try:
                api_read_limiter.wait()
                _race_resp = kalshi_client.get_order(order_id)
                _race_ord = _race_resp.get('order', _race_resp) if isinstance(_race_resp, dict) else {}
                _race_fills = _parse_fill_count(_race_ord)
                _already_counted = bot.get('_counted_dog_fills', {}).get(order_id, 0)
                if _race_fills <= 0:
                    print(f'👻 WS CANCEL-RACE GHOST: {bot_id} fill event for old order {order_id[:12]} but 0 fills on Kalshi — ignoring')
                    bot_log('PHANTOM_WS_GHOST_FILL_BLOCKED', bot_id, {
                        'old_order_id': order_id[:12], 'kalshi_fills': 0,
                    }, level='WARN')
                    continue
                if _race_fills <= _already_counted:
                    print(f'👻 WS CANCEL-RACE DEDUP: {bot_id} order {order_id[:12]} has {_race_fills} fills but {_already_counted} already counted — skipping')
                    continue
                # Only count the NEW fills beyond what was already hedged
                count = _race_fills - _already_counted
                bot.setdefault('_counted_dog_fills', {})[order_id] = _race_fills
            except Exception as _race_err:
                print(f'⚠ WS CANCEL-RACE CHECK FAILED: {bot_id} {_race_err} — ignoring fill to be safe')
                continue
            matched = 'dog'
            # Cancel the NEW order that replaced this one — otherwise it stays live and creates orphans
            _current_oid = bot.get('dog_order_id')
            if _current_oid and _current_oid != order_id:
                threading.Thread(target=lambda oid=_current_oid: _safe_cancel(oid, f'cancel_race_cleanup_{bot_id}'), daemon=True).start()
            bot['dog_order_id'] = order_id  # restore old order ID so hedge can proceed
            print(f'🔍 WS CANCEL-RACE CATCH: {bot_id} fill on old order {order_id[:12]} VERIFIED ({_race_fills} fills), cancelled new order {(_current_oid or "?")[:12]}')
        elif order_id == bot.get('fav_order_id') and bot['status'] == 'fav_hedge_posted':
            matched = 'fav'
        if not matched:
            continue

        # Lock to prevent race with hedge thread modifying same bot
        with ws_fill_lock:
            qty_bot = bot.get('quantity', 1)
            if matched == 'dog':
                bot['dog_fill_qty'] = bot.get('dog_fill_qty', 0) + count
                if bot['dog_side'] == 'yes':
                    bot['yes_fill_qty'] = bot['dog_fill_qty']
                else:
                    bot['no_fill_qty'] = bot['dog_fill_qty']
                if bot['dog_fill_qty'] >= qty_bot and not bot.get('_hedge_fired'):
                    # SPEED CRITICAL — hedge worker gets the job IMMEDIATELY, log after
                    bot['_hedge_fired'] = True
                    bot['dog_filled_at'] = time.time()
                    bot['status'] = 'dog_filled'
                    _hedge_worker_queue.put((_execute_phantom_hedge, (bot_id,)))
                    # Skip save_state — json.dump GIL contention blocks hedge worker (deferred to hedge fn line 3508)
                    break
                elif bot['dog_fill_qty'] > 0 and not bot.get('_hedge_fired'):
                    # Partial fill — hedge FIRST, cancel remainder async (don't block hot path)
                    bot['_hedge_fired'] = True
                    bot['dog_filled_at'] = time.time()
                    bot['_original_qty'] = qty_bot
                    bot['_partial_hedge_qty'] = bot['dog_fill_qty']
                    bot['status'] = 'dog_filled'
                    _hedge_worker_queue.put((_execute_phantom_hedge, (bot_id,)))
                    _cancel_oid = bot.get('dog_order_id') if bot['dog_fill_qty'] < qty_bot else None
                    if _cancel_oid:
                        threading.Thread(target=lambda oid=_cancel_oid: _safe_cancel(oid, f'partial_fill_{bot_id}'), daemon=True).start()
                    print(f'⚡ WS PHANTOM PARTIAL HEDGE: {bot_id} {bot["dog_fill_qty"]}/{qty_bot} filled → hedging now, cancelling rest async')
                    # Skip save_state — deferred to hedge fn (line 3508)
                    break
                print(f'👻 WS PHANTOM FILL: {bot_id} +{count} → {bot["dog_fill_qty"]}/{qty_bot}')
            elif matched == 'fav':
                bot['fav_fill_qty'] = bot.get('fav_fill_qty', 0) + count
                if bot['fav_side'] == 'yes':
                    bot['yes_fill_qty'] = bot['fav_fill_qty']
                else:
                    bot['no_fill_qty'] = bot['fav_fill_qty']
                print(f'👻 WS PHANTOM FAV FILL: {bot_id} +{count} → {bot["fav_fill_qty"]}/{qty_bot}')
            save_state()
        break

    # ── Apex Market Maker: WS fill matching ──────────────────────────
    for bot_id, bot in list(active_bots.items()):
        if bot.get('bot_category') != 'ladder_arb':
            continue
        if bot.get('type') != 'apex_mm':
            continue
        status = bot.get('status', '')
        if status not in ('market_making_active', 'mm_exiting'):
            continue

        matched_side = None
        matched_price = None
        is_exit_fill = False

        # Check YES orders
        for price_str, level in bot.get('yes_orders', {}).items():
            if order_id == level.get('oid'):
                matched_side = 'yes'
                matched_price = int(price_str)
                break

        # Check NO orders
        if not matched_side:
            for price_str, level in bot.get('no_orders', {}).items():
                if order_id == level.get('oid'):
                    matched_side = 'no'
                    matched_price = int(price_str)
                    break

        # Check single exit order (amend system)
        is_amend_exit_fill = False
        if not matched_side:
            for _exit_side in ('yes', 'no'):
                if order_id == bot.get(f'_{_exit_side}_exit_oid'):
                    matched_side = _exit_side
                    is_amend_exit_fill = True
                    # Price comes from the exit order we posted
                    matched_price = bot.get('_exit_price', 0)
                    break

        # Check exit sell orders (end-of-game sellback)
        if not matched_side:
            for _exit_side in ('yes', 'no'):
                sell_info = bot.get('_exit_sell_oids', {}).get(_exit_side, {})
                if order_id == sell_info.get('oid'):
                    is_exit_fill = True
                    matched_side = _exit_side
                    break

        # Fallback: check ALL ever-posted order IDs (catches late fills after cycle reset)
        _is_late_fill = False
        if not matched_side:
            if order_id in (bot.get('_all_placed_order_ids') or []):
                # DEDUP: skip if we already fully counted this order's fills
                _already_counted = bot.get('_counted_order_fills', {}).get(order_id, 0)
                # Late fill from old cycle — VERIFY with Kalshi before trusting WS
                _late_price = 0
                _late_verified_fills = 0
                _late_status = '?'
                try:
                    api_read_limiter.wait()
                    _late_resp = kalshi_client.get_order(order_id)
                    _late_ord = _late_resp.get('order', _late_resp) if isinstance(_late_resp, dict) else {}
                    # Parse price: try _dollars (float str), then _fp, then int field
                    _price_key = 'no_price' if side == 'no' else 'yes_price'
                    _dollars = _late_ord.get(f'{_price_key}_dollars')
                    if _dollars:
                        _late_price = int(round(float(_dollars) * 100))
                    else:
                        _fp = _late_ord.get(f'{_price_key}_fp')
                        if _fp:
                            _late_price = int(float(_fp))
                        else:
                            _late_price = int(_late_ord.get(_price_key, 0) or 0)
                    _late_verified_fills = _parse_fill_count(_late_ord)
                    _late_status = _late_ord.get('status', '?')
                except Exception:
                    pass
                # Ghost fill check: if Kalshi says 0 fills, this is a stale WS event — IGNORE
                if _late_verified_fills <= 0:
                    print(f'👻 APEX MM GHOST FILL BLOCKED: {bot_id} {side.upper()} +{count} on old order {order_id[:12]} — Kalshi says {_late_verified_fills} fills (status={_late_status})')
                    bot_log('APEX_MM_GHOST_FILL_BLOCKED', bot_id, {
                        'order_id': order_id, 'side': side, 'ws_count': count,
                        'kalshi_fills': _late_verified_fills, 'kalshi_status': _late_status,
                    }, level='WARN')
                    continue  # skip this fill entirely
                # DEDUP: only count NEW fills beyond what we already tracked
                _new_fills = max(0, _late_verified_fills - _already_counted)
                if _new_fills <= 0:
                    print(f'👻 APEX MM LATE FILL DEDUP: {bot_id} {side.upper()} order {order_id[:12]} has {_late_verified_fills} fills but {_already_counted} already counted — skipping')
                    continue
                # Record that we've counted these fills
                bot.setdefault('_counted_order_fills', {})[order_id] = _late_verified_fills
                matched_side = side
                matched_price = _late_price
                count = _new_fills  # Only add the delta, not total
                _is_late_fill = True
                print(f'🚨 APEX MM LATE FILL (verified): {bot_id} {side.upper()} +{count} @{_late_price}c on order {order_id[:12]} (kalshi_total={_late_verified_fills} already_counted={_already_counted})')
                bot_log('APEX_MM_LATE_FILL', bot_id, {
                    'order_id': order_id, 'side': side, 'new_fills': count,
                    'kalshi_total': _late_verified_fills, 'already_counted': _already_counted,
                    'price': _late_price, 'kalshi_status': _late_status,
                    'net_yes': bot.get('net_yes', 0), 'net_no': bot.get('net_no', 0),
                }, level='WARN')

        if not matched_side:
            continue

        with ws_fill_lock:
            if is_amend_exit_fill:
                # Exit order fill — closing position via the amend system
                opposite = 'no' if matched_side == 'yes' else 'yes'
                opp_held = bot.get(f'net_{opposite}', 0)
                close_qty = min(count, opp_held)
                exit_price = matched_price or bot.get('_exit_price', 0)

                # CRITICAL: track exit fills in _counted_order_fills so late-fill
                # path doesn't re-add them as inventory when exit_oid is cleared
                if order_id:
                    _cum = bot.setdefault('_counted_order_fills', {})
                    _cum[order_id] = _cum.get(order_id, 0) + count

                if close_qty > 0:
                    _apex_mm_record_round_trip(bot_id, bot, matched_side, exit_price, close_qty)
                    bot['_exit_fill_qty'] = bot.get('_exit_fill_qty', 0) + close_qty
                    print(f'💰 WS APEX MM EXIT FILL: {bot_id} {matched_side.upper()} +{count} @{exit_price}c → closed {close_qty}x (exit {bot["_exit_fill_qty"]}/{bot.get("_exit_total_qty",0)})')

                # Log fill
                bot.setdefault('_fill_log', []).append({
                    'side': matched_side, 'price': exit_price, 'qty': count,
                    'net_yes': bot.get('net_yes', 0), 'net_no': bot.get('net_no', 0),
                    'ts': time.time(), 'is_exit': True,
                })

                # Check if flat → cycle reset
                net_yes = bot.get('net_yes', 0)
                net_no = bot.get('net_no', 0)
                if net_yes == 0 and net_no == 0:
                    bot[f'_{matched_side}_exit_oid'] = None
                    threading.Thread(target=_apex_mm_cycle_refill, args=(bot_id, bot), daemon=True).start()
                    print(f'📊 APEX MM FLAT: {bot_id} → cycle refill')
                elif abs(net_yes - net_no) > 0:
                    # Still holding some — amend exit order with reduced count + refill freed slots
                    threading.Thread(target=_apex_mm_amend_exit, args=(bot_id, bot, matched_side), daemon=True).start()
                    # Slot-recovery: refill freed entry rung if gates pass
                    if close_qty > 0:
                        threading.Thread(target=_apex_mm_refill_entry, args=(bot_id, bot, close_qty), daemon=True).start()

                bot_log('APEX_MM_EXIT_FILL', bot_id, {
                    'side': matched_side, 'price': exit_price, 'count': count,
                    'close_qty': close_qty, 'net_yes': net_yes, 'net_no': net_no,
                    'realized_pnl': bot.get('realized_pnl_cents', 0),
                })

            elif is_exit_fill:
                # Exit sell fill (end-of-game sellback) — handled by _apex_mm_exit_tick
                # Track in _counted_order_fills to prevent late-fill re-count
                if order_id:
                    _cum = bot.setdefault('_counted_order_fills', {})
                    _cum[order_id] = _cum.get(order_id, 0) + count
                sell_info = bot.get('_exit_sell_oids', {}).get(matched_side, {})
                old_fill = sell_info.get('_ws_fill_qty', 0)
                sell_info['_ws_fill_qty'] = old_fill + count
                print(f'🚪 WS APEX MM SELLBACK FILL: {bot_id} {matched_side.upper()} +{count}')
            else:
                # Ladder fill (or late fill from old cycle) — update inventory
                # CRITICAL: re-check _counted_order_fills under lock for late fills
                # Two WS threads can both read already_counted=0 outside the lock,
                # both pass the dedup check, both enter here — second one double-counts
                if _is_late_fill:
                    _recheck = bot.get('_counted_order_fills', {}).get(order_id, 0)
                    if _recheck >= _late_verified_fills:
                        print(f'🛡️ APEX MM LATE FILL DEDUP (lock): {bot_id} {matched_side.upper()} order {order_id[:12]} already counted {_recheck} under lock — skipping')
                        save_state()
                        break
                    # Write count under lock to prevent next thread from double-adding
                    bot.setdefault('_counted_order_fills', {})[order_id] = _late_verified_fills
                    count = max(0, _late_verified_fills - _recheck)
                    if count <= 0:
                        save_state()
                        break

                if not _is_late_fill:
                    orders_dict = bot['yes_orders'] if matched_side == 'yes' else bot['no_orders']
                    level = orders_dict.get(str(matched_price), {})
                    # RE-VERIFY: if cycle_reset cleared this OID under the lock,
                    # it already counted these fills — don't double-count
                    if level.get('oid') != order_id:
                        _already = bot.get('_counted_order_fills', {}).get(order_id, 0)
                        print(f'🛡️ APEX MM FILL DEDUP: {bot_id} {matched_side.upper()} order {order_id[:12]} OID cleared by cycle_reset (counted={_already}) — skipping')
                        bot_log('APEX_MM_FILL_DEDUP', bot_id, {
                            'side': matched_side, 'price': matched_price, 'ws_count': count,
                            'already_counted': _already, 'order_id': order_id,
                        })
                        save_state()
                        break
                    level['fill_qty'] = level.get('fill_qty', 0) + count
                    # Track cumulative fills per order for late-fill dedup
                    if order_id:
                        _cum = bot.setdefault('_counted_order_fills', {})
                        _cum[order_id] = _cum.get(order_id, 0) + count

                # Add to inventory
                _was_flat = bot.get(f'net_{matched_side}', 0) == 0
                bot[f'net_{matched_side}'] = bot.get(f'net_{matched_side}', 0) + count
                bot[f'total_{matched_side}_cost'] = bot.get(f'total_{matched_side}_cost', 0) + (matched_price * count)
                total_qty = bot[f'net_{matched_side}']
                bot[f'avg_{matched_side}_cost'] = round(bot[f'total_{matched_side}_cost'] / total_qty) if total_qty > 0 else 0
                # Track when inventory was first acquired (for round-trip timing)
                if _was_flat:
                    bot[f'_{matched_side}_inv_since'] = time.time()
                bot[f'_last_{matched_side}_fill_at'] = time.time()

                print(f'📊 WS APEX MM FILL: {bot_id} {matched_side.upper()} +{count} @{matched_price}c → net_{matched_side}={bot[f"net_{matched_side}"]} avg={bot[f"avg_{matched_side}_cost"]}c')

                # Log fill for card display
                bot.setdefault('_fill_log', []).append({
                    'side': matched_side, 'price': matched_price, 'qty': count,
                    'net_yes': bot.get('net_yes', 0), 'net_no': bot.get('net_no', 0),
                    'ts': time.time(),
                })
                # Keep last 50 fills
                if len(bot['_fill_log']) > 50:
                    bot['_fill_log'] = bot['_fill_log'][-50:]

                # ── Velocity Gate: detect rapid fills on same side ──
                _vf_now = time.time()
                _vfills = bot.setdefault('_velocity_fills', [])
                _vfills.append({'ts': _vf_now, 'side': matched_side})
                # Prune entries older than 2s
                bot['_velocity_fills'] = [v for v in _vfills if _vf_now - v['ts'] <= 2.0]
                # Check: 3+ fills on same side within 500ms → cancel remaining entry rungs
                if not bot.get('_velocity_gated'):
                    _vg_count = sum(1 for v in bot['_velocity_fills']
                                    if v['side'] == matched_side and _vf_now - v['ts'] <= 0.5)
                    if _vg_count >= 3:
                        bot['_velocity_gated'] = True
                        bot['_velocity_gated_side'] = matched_side
                        bot['_velocity_gated_at'] = _vf_now
                        print(f'🚨 APEX MM VELOCITY GATE: {bot_id} {matched_side.upper()} — {_vg_count} fills in 500ms, cancelling entry orders')
                        bot_log('APEX_MM_VELOCITY_GATE', bot_id, {
                            'side': matched_side, 'fills_in_window': _vg_count,
                            'net_yes': bot.get('net_yes', 0), 'net_no': bot.get('net_no', 0),
                        }, level='WARN')
                        # Cancel unfilled entry orders on the swept side (background thread)
                        _vg_side_key = f'{matched_side}_orders'
                        _vg_to_cancel = []
                        for _vg_p, _vg_lvl in list(bot.get(_vg_side_key, {}).items()):
                            _vg_oid = _vg_lvl.get('oid')
                            if _vg_oid and _vg_lvl.get('fill_qty', 0) < _vg_lvl.get('qty', 1):
                                _vg_to_cancel.append((_vg_oid, _vg_lvl))
                        if _vg_to_cancel:
                            def _velocity_cancel(_cancel_list, _bid=bot_id):
                                for _oid, _lvl in _cancel_list:
                                    try:
                                        _safe_cancel(_oid, f'velocity_gate_{_bid}')
                                        _lvl['oid'] = None
                                    except Exception:
                                        pass
                            threading.Thread(target=_velocity_cancel, args=(_vg_to_cancel,), daemon=True).start()

                # Check if this fill closes opposite position (round trip)
                opposite = 'no' if matched_side == 'yes' else 'yes'
                opp_held = bot.get(f'net_{opposite}', 0)
                if opp_held > 0:
                    close_qty = min(count, opp_held)
                    _apex_mm_record_round_trip(bot_id, bot, matched_side, matched_price, close_qty)
                    # Also deduct from this side since it was used to close
                    bot[f'net_{matched_side}'] = max(0, bot.get(f'net_{matched_side}', 0) - close_qty)
                    bot[f'total_{matched_side}_cost'] = max(0, bot.get(f'total_{matched_side}_cost', 0) - (matched_price * close_qty))
                    if bot[f'net_{matched_side}'] > 0:
                        bot[f'avg_{matched_side}_cost'] = round(bot[f'total_{matched_side}_cost'] / bot[f'net_{matched_side}'])
                    else:
                        bot[f'avg_{matched_side}_cost'] = 0
                        bot[f'total_{matched_side}_cost'] = 0

                # If ladder RT made us flat, cancel exit order NOW to prevent orphan fills
                if opp_held > 0 and bot.get('net_yes', 0) == 0 and bot.get('net_no', 0) == 0:
                    for _cancel_exit_side in ('yes', 'no'):
                        _cancel_exit_oid = bot.get(f'_{_cancel_exit_side}_exit_oid')
                        if _cancel_exit_oid:
                            bot[f'_{_cancel_exit_side}_exit_oid'] = None  # clear FIRST to prevent WS re-match
                            threading.Thread(target=_safe_cancel, args=(_cancel_exit_oid, f'rt_flat_cancel_{bot_id}'), daemon=True).start()
                            print(f'🛡️ APEX MM RT FLAT: cancelled {_cancel_exit_side} exit {_cancel_exit_oid[:12]} to prevent orphan')

                bot_log('APEX_MM_WS_FILL', bot_id, {
                    'side': matched_side, 'price': matched_price, 'count': count,
                    'net_yes': bot.get('net_yes', 0), 'net_no': bot.get('net_no', 0),
                    'realized_pnl': bot.get('realized_pnl_cents', 0),
                })

                # Amend exit order: create or update single exit order
                if status == 'market_making_active':
                    threading.Thread(
                        target=_apex_mm_amend_exit,
                        args=(bot_id, bot, matched_side),
                        daemon=True
                    ).start()

            save_state()
        break


def _precalc_phantom_hedge(dog_price, target_width, dog_side, qty):
    """Pre-calculate the hedge price for instant fire on dog fill.
    FALLBACK when no live bid is available — the WS path uses the actual bid.
    No ceiling cap — arb completes at whatever combined price."""
    hedge = 100 - dog_price  # best-case estimate, actual bid used when available
    if hedge < 1:
        return 0
    return hedge


def _execute_phantom_hedge(bot_id):
    """Post the favorite hedge immediately after the dog fills.
    Called from WS fill handler in a background thread for speed.
    Posts at fav BID (maker) from WS cache — speed gets us first in queue."""
    try:
        bot = active_bots.get(bot_id)
        if not bot or bot.get('status') in ('stopped', 'completed'):
            return

        # Guard: monitor path may have already posted a hedge
        with ws_fill_lock:
            if bot.get('fav_order_id'):
                print(f'⚡ WS HEDGE SKIPPED: {bot_id} monitor already posted fav_order_id={bot["fav_order_id"][:12]}')
                return

        ticker = bot['ticker']
        hedge_ticker = bot.get('hedge_ticker', ticker)
        fav_side = bot['fav_side']
        dog_side = bot['dog_side']
        qty = bot.get('_partial_hedge_qty') or bot.get('quantity', 1)
        dog_price = bot['dog_price']

        # Post at fav BID — maker order, first in queue with our speed
        # ALWAYS read from ws_manager first (real-time), fall back to bot cache
        _is_cross = hedge_ticker != ticker
        fav_bid = 0
        fav_ask = 0
        _ws_ticker = hedge_ticker if _is_cross else ticker
        if ws_manager:
            _ws_data = ws_manager.get_price(_ws_ticker)
            if _ws_data:
                fav_bid = _ws_data.get(f'{fav_side}_bid', 0)
                fav_ask = _ws_data.get(f'{fav_side}_ask', 0)
                if fav_ask <= 0:
                    _opp = _ws_data.get(f'{"no" if fav_side == "yes" else "yes"}_bid', 0)
                    fav_ask = (100 - _opp) if _opp > 0 else 0
        if fav_bid <= 0:
            # WS unavailable: fall back to bot cache
            _pfx = 'live_hedge_' if _is_cross else 'live_'
            fav_bid = bot.get(f'{_pfx}{fav_side}_bid', 0)
            if fav_ask <= 0:
                opp_bid = bot.get(f'{_pfx}{"no" if fav_side == "yes" else "yes"}_bid', 0)
                fav_ask = (100 - opp_bid) if opp_bid > 0 else 0
        fav_spread = (fav_ask - fav_bid) if fav_ask > 0 and fav_bid > 0 else 0

        if fav_bid > 0:
            # Always post at bid — no ceiling cap, arb completes at whatever price
            hedge_price = fav_bid
        else:
            # No WS bid available — fall back to precalc
            hedge_price = bot.get('_precalc_hedge_price') or 0
            if hedge_price < 1:
                hedge_price = _precalc_phantom_hedge(dog_price, bot.get('target_width', 5), dog_side, qty)

        if hedge_price < 1:
            print(f'   ⚠ Hedge price {hedge_price}¢ too low — deferring')
            bot_log('PHANTOM_HEDGE_TOO_LOW', bot_id, {'hedge_price': hedge_price, 'dog_price': dog_price, 'fav_bid': fav_bid, 'path': 'ws_fast'})
            bot['status'] = 'dog_filled'
            return

        # Record raw hedge speed RIGHT before API call — nothing between this and HTTP send
        if not bot.get('dog_filled_at'):
            bot['dog_filled_at'] = time.time()
        _raw_fill_at = bot.get('dog_filled_at')
        _is_retry = bot.get('raw_hedge_ms') is not None
        if _raw_fill_at and not _is_retry:
            _raw_ms = (time.time() - _raw_fill_at) * 1000
            bot['raw_hedge_ms'] = round(_raw_ms, 1)
            _record_latency('raw_hedge_phantom', _raw_ms, {'bot_id': bot_id, 'type': 'phantom'})
        # SPEED CRITICAL — straight to API, no rate limiter
        fav_resp, actual_fav_price = create_order_maker(
            ticker=hedge_ticker, side=fav_side, action='buy',
            count=qty, price=hedge_price, priority=True,
            skip_rate_limit=True
        )
        # Round trip measurement
        _rt_ms = (time.time() - _raw_fill_at) * 1000 if _raw_fill_at and not _is_retry else None
        if _rt_ms is not None:
            bot['hedge_latency_ms'] = round(_rt_ms, 1)
            _record_latency('fill_to_hedge_phantom', _rt_ms, {'bot_id': bot_id, 'type': 'phantom', 'fav_price': actual_fav_price})

        fav_order_id = fav_resp['order']['order_id']
        bot['fav_order_id'] = fav_order_id
        bot['fav_price'] = actual_fav_price
        bot['status'] = 'fav_hedge_posted'
        bot['fav_posted_at'] = time.time()
        bot['fav_walk_count'] = 0
        bot['fav_last_walk_at'] = None
        bot['_taker_fired'] = False
        if fav_side == 'yes':
            bot['yes_price'] = actual_fav_price
            bot['yes_order_id'] = fav_order_id
        else:
            bot['no_price'] = actual_fav_price
            bot['no_order_id'] = fav_order_id
        save_state()  # deferred from WS handler — save after hedge is posted

        print(f'👻 PHANTOM HEDGE: {bot_id} {fav_side.upper()} @{actual_fav_price}¢ | raw={round(_raw_ms, 1) if _raw_fill_at else "?"}ms rt={round(_rt_ms, 1) if _rt_ms else "?"}ms')
        _obi_at_hedge = _obi_snapshot(bot)
        bot['_obi_at_fill'] = _obi_at_hedge  # stash for trade record later
        bot_log('PHANTOM_WS_HEDGE_POSTED', bot_id, {
            'fav_side': fav_side, 'fav_price': actual_fav_price,
            'fav_bid': fav_bid, 'fav_ask': fav_ask, 'fav_spread': fav_spread,
            'fav_order_id': fav_order_id[:12], 'dog_price': dog_price,
            'combined': dog_price + actual_fav_price, 'qty': qty,
            'path': 'ws_fast',
            'obi': _obi_at_hedge,
        })
        _audit('PHANTOM_WS_HEDGE_POSTED', bot_id, {
            'ticker': ticker, 'fav_side': fav_side, 'fav_price': actual_fav_price,
            'fav_order_id': fav_order_id, 'dog_price': dog_price, 'qty': qty,
        })
        # Async: verify actual dog fill price (non-blocking, after hedge is already placed)
        def _verify_dog_price():
            try:
                vp = get_actual_fill_price(bot.get('dog_order_id'), dog_side)
                if vp and vp != dog_price:
                    bot['dog_price'] = vp
                    print(f'   📋 Dog fill price verified: {dog_price}¢ → {vp}¢')
                    save_state()
            except Exception:
                pass
        threading.Thread(target=_verify_dog_price, daemon=True).start()

        # ── Delayed taker cross: tiered maker window, then grab ask if profitable ──
        # Wider spreads = more room to wait as maker (saves 40-50¢ taker fee per round)
        _tp_bot_id = bot_id
        _tp_dog_price = dog_price
        _tp_fav_side = fav_side
        _tp_fav_order_id = fav_order_id
        _tp_hedge_ticker = hedge_ticker
        _tp_qty = qty
        _tp_combined = dog_price + actual_fav_price  # combined at time of posting
        def _delayed_taker_cross():
            try:
                # DISABLED: crossing spread costs 2-5c (bid→ask gap), which is the entire
                # profit margin. Hedge stays as maker at bid. Walk system handles the rest.
                return
                _maker_wait = 1.0
                time.sleep(_maker_wait)
                _b = active_bots.get(_tp_bot_id)
                if not _b or _b.get('status') != 'fav_hedge_posted':
                    return  # bot completed/cancelled/status changed
                if _b.get('fav_fill_qty', 0) >= _tp_qty:
                    return  # already filled as maker
                if _b.get('fav_order_id') != _tp_fav_order_id:
                    return  # order changed (already amended/crossed by monitor)
                # Get current ask from WS cache
                _ask = _b.get(f'live_{_tp_fav_side}_ask', 0)
                if _tp_hedge_ticker != _b.get('ticker'):
                    _ask = _b.get(f'live_hedge_{_tp_fav_side}_ask', 0) or _ask
                if _ask <= 0:
                    return  # no ask data
                _cross_comb = _tp_dog_price + _ask
                if _cross_comb > 100:
                    return  # past breakeven — sellback territory
                # Cross the spread: cancel maker, place taker at ask
                _phantom_drop_lock.acquire()
                try:
                    # Re-check after acquiring lock
                    if _b.get('fav_fill_qty', 0) >= _tp_qty or _b.get('fav_order_id') != _tp_fav_order_id:
                        return
                    api_rate_limiter.wait()
                    try:
                        kalshi_client.cancel_order(_tp_fav_order_id)
                    except Exception as _ce:
                        # May have filled during cancel
                        try:
                            api_read_limiter.wait()
                            _chk = kalshi_client.get_order(_tp_fav_order_id)
                            _chk_ord = _chk.get('order', _chk) if isinstance(_chk, dict) else {}
                            if _parse_fill_count(_chk_ord) >= _tp_qty:
                                _b['fav_fill_qty'] = _tp_qty
                                print(f'💰 PHANTOM TAKER SKIP: {_tp_bot_id} filled as maker during cancel')
                                return
                        except Exception:
                            pass
                        return  # cancel failed, don't proceed
                    _already_filled = _b.get('fav_fill_qty', 0)
                    _remaining = _tp_qty - _already_filled
                    if _remaining <= 0:
                        return
                    price_kwargs = {'yes_price': _ask} if _tp_fav_side == 'yes' else {'no_price': _ask}
                    api_rate_limiter.wait()
                    resp = kalshi_client.create_order(
                        ticker=_tp_hedge_ticker, side=_tp_fav_side, action='buy',
                        count=_remaining, order_type='limit', **price_kwargs
                    )
                    new_oid = resp.get('order', {}).get('order_id', '')
                    _b.setdefault('_all_hedge_order_ids', []).append(_tp_fav_order_id)
                    _b['fav_order_id'] = new_oid
                    _b['fav_price'] = _ask
                    _b['_fav_was_taker'] = True
                    _b['fav_walk_count'] = _b.get('fav_walk_count', 0) + 1
                    if _tp_fav_side == 'yes':
                        _b['yes_price'] = _ask
                    else:
                        _b['no_price'] = _ask
                    save_state()
                    _profit = 100 - _cross_comb
                    print(f'💰 PHANTOM FAST TAKER: {_tp_bot_id} crossed ask {_ask}¢ (combined={_cross_comb}¢ profit={_profit}¢/ea) after {_maker_wait}s maker window')
                    bot_log('PHANTOM_FAST_TAKER_CROSS', _tp_bot_id, {
                        'cross_price': _ask, 'combined': _cross_comb,
                        'dog_price': _tp_dog_price, 'profit_per': _profit,
                        'maker_price': actual_fav_price,
                        'maker_wait_s': _maker_wait,
                    })
                finally:
                    if _phantom_drop_lock.locked():
                        _phantom_drop_lock.release()
            except Exception as e:
                print(f'⚠ PHANTOM FAST TAKER {_tp_bot_id}: {e}')
        threading.Thread(target=_delayed_taker_cross, daemon=True).start()
    except Exception as e:
        print(f'❌ WS PHANTOM HEDGE {bot_id}: {e}')
        import traceback
        traceback.print_exc()
        try:
            bot_log('PHANTOM_WS_HEDGE_ERROR', bot_id, {'error': str(e)[:300], 'path': 'ws_fast'}, level='ERROR')
            _audit('PHANTOM_WS_HEDGE_ERROR', bot_id, {'error': str(e)[:200]})
        except Exception:
            pass
        bot = active_bots.get(bot_id)
        if bot:
            # Only reset to dog_filled if the order was NOT already placed.
            # If fav_order_id exists, the hedge is live on Kalshi — don't lose track of it.
            if bot.get('fav_order_id'):
                bot['status'] = 'fav_hedge_posted'
                if not bot.get('fav_posted_at'):
                    bot['fav_posted_at'] = time.time()
            else:
                bot['status'] = 'dog_filled'  # fallback to monitor retry


# --- anchor_ladder functions removed (dead code) ---
# _execute_phantom_ladder_hedge, _ladder_sweep_then_hedge,
# _phantom_ladder_sell_back were all anchor_ladder-specific.
# Only single phantom (anchor_dog) remains.


def _execute_ws_dog_post(bot_id):
    """
    Post the underdog leg immediately after the favorite fills.
    Called from WS fill handler in a background thread.
    """
    with ws_fill_lock:
        bot = active_bots.get(bot_id)
        if not bot or bot['status'] in ('stopped', 'completed'):
            if bot:
                bot.pop('_ws_fill_handling', None)
            return

        # Double-check status — another thread may have already handled this
        if bot['status'] != 'fav_posted':
            bot.pop('_ws_fill_handling', None)
            return

        now = time.time()
        ticker = bot['ticker']
        qty = bot['quantity']
        fav_side = bot.get('fav_side', 'yes')
        dog_side = bot.get('dog_side', 'no' if fav_side == 'yes' else 'yes')
        dog_price = bot.get('dog_price', bot['no_price'] if dog_side == 'no' else bot['yes_price'])
        fav_price = bot.get('fav_price', bot['yes_price'] if fav_side == 'yes' else bot['no_price'])
        fav_filled = bot.get('yes_fill_qty', 0) if fav_side == 'yes' else bot.get('no_fill_qty', 0)

        try:
            # Fetch fresh orderbook to verify arb is still viable
            try:
                api_read_limiter.wait()
                ob_data = _normalize_orderbook(kalshi_client.get_market_orderbook(ticker))
                ob = ob_data.get('orderbook', ob_data)
                if dog_side == 'no':
                    dog_levels = sorted(ob.get('no', []),
                        key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
                    live_dog_bid = (dog_levels[0][0] if isinstance(dog_levels[0], list) else dog_levels[0].get('price', 0)) if dog_levels else 0
                else:
                    dog_levels = sorted(ob.get('yes', []),
                        key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
                    live_dog_bid = (dog_levels[0][0] if isinstance(dog_levels[0], list) else dog_levels[0].get('price', 0)) if dog_levels else 0

                # NEVER post above the current bid
                if dog_price > live_dog_bid and live_dog_bid > 0:
                    dog_price = live_dog_bid
                    print(f'📉 WS PHANTOM: Adjusted {dog_side.upper()} price to bid {live_dog_bid}¢')
            except Exception as ob_err:
                print(f'⚠ WS PHANTOM: Orderbook check failed: {ob_err} — using planned price')

            # Verify arb width still makes sense
            actual_profit = 100 - fav_price - dog_price
            min_width = max(1, bot.get('arb_width', bot.get('profit_per', 3)) // 2)
            if actual_profit < min_width:
                print(f'⚠ WS PHANTOM: Arb no longer viable for {bot_id}: profit={actual_profit}¢ < min={min_width}¢ — letting SL handle')
                if fav_side == 'yes':
                    bot['status'] = 'yes_filled'
                else:
                    bot['status'] = 'no_filled'
                bot['first_fill_at'] = now
                bot['first_leg'] = fav_side
                bot['posted_at'] = now
                bot.pop('_ws_fill_handling', None)
                save_state()
                return

            # Post the underdog order
            api_rate_limiter.wait()
            if dog_side == 'no':
                dog_order = kalshi_client.create_order(
                    ticker=ticker, side='no', action='buy',
                    count=qty, no_price=dog_price, post_only=True)
                dog_oid = _extract_order_id(dog_order, f'WS phantom dog post {bot_id}')
                if not dog_oid:
                    return
                bot['no_order_id'] = dog_oid
                bot['no_price'] = dog_price
                bot['yes_fill_qty'] = fav_filled
                bot['status'] = 'yes_filled'
            else:
                dog_order = kalshi_client.create_order(
                    ticker=ticker, side='yes', action='buy',
                    count=qty, yes_price=dog_price, post_only=True)
                dog_oid = _extract_order_id(dog_order, f'WS phantom dog post {bot_id}')
                if not dog_oid:
                    return
                bot['yes_order_id'] = dog_oid
                bot['yes_price'] = dog_price
                bot['no_fill_qty'] = fav_filled
                bot['status'] = 'no_filled'

            bot['first_fill_at'] = now
            bot['first_leg'] = fav_side
            bot['posted_at'] = now
            bot['profit_per'] = 100 - bot['yes_price'] - bot['no_price']

            # Subscribe to the new order's ticker on WS (already subscribed, but ensure fill tracking)
            if ws_manager and ws_manager.connected:
                ws_manager.add_ticker(ticker)

            bot_log('FAV_FILLED_DOG_POSTED', bot_id, {
                'fav_side': fav_side, 'fav_price': fav_price,
                'dog_side': dog_side, 'dog_price': dog_price,
                'profit_per': bot['profit_per'],
                'source': 'ws_realtime'
            })
            print(f'⚡ WS FAV-FILL → PHANTOM POSTED: {bot_id} {fav_side.upper()} filled at {fav_price}¢ → '
                  f'posted {dog_side.upper()} at {dog_price}¢ '
                  f'(profit target: {bot["profit_per"]}¢) [INSTANT]')
            save_state()

        except Exception as err:
            print(f'⚠ WS PHANTOM post failed for {bot_id}: {err} — monitor will retry')

        bot.pop('_ws_fill_handling', None)

        # ── Race-condition guard: dog side may have filled while we held the lock ──
        # If the WS fill handler already incremented no_fill_qty (or yes_fill_qty)
        # while _ws_fill_handling was True, it would have skipped completion.
        # Re-check now and trigger completion if both legs are done.
        if bot and bot.get('status') not in ('stopped', 'completed', 'waiting_repeat'):
            yes_f = bot.get('yes_fill_qty', 0)
            no_f  = bot.get('no_fill_qty', 0)
            q     = bot.get('quantity', 0)
            if yes_f >= q and no_f >= q:
                print(f'⚡ WS RACE FIX: {bot_id} dog already filled during post — completing now!')
                bot['_ws_fill_handling'] = True
                # Release lock briefly, then call completion
                threading.Thread(
                    target=_execute_ws_completion,
                    args=(bot_id,),
                    daemon=True
                ).start()


def _execute_ws_completion(bot_id):
    """
    Handle both-legs-filled completion instantly from WS fill event.
    Called in a background thread.
    """
    with ws_fill_lock:
        bot = active_bots.get(bot_id)
        if not bot or bot['status'] in ('stopped', 'completed'):
            if bot:
                bot.pop('_ws_fill_handling', None)
            return

        # ── Guard: if monitor is amending this bot, let the monitor record the trade ──
        # Without this, BOTH WS handler and monitor record a trade → double-count PnL.
        if bot.get('status') in ('amending_yes', 'amending_no'):
            print(f'⚡ WS COMPLETION SKIP: {bot_id} is {bot["status"]} — monitor will record trade')
            bot.pop('_ws_fill_handling', None)
            return

        # ── Guard: if monitor already recorded a trade for this cycle, skip ──
        if bot.get('_trade_recorded'):
            print(f'⚡ WS COMPLETION SKIP: {bot_id} — trade already recorded by monitor')
            bot.pop('_ws_fill_handling', None)
            return

        now = time.time()
        ticker = bot['ticker']
        qty = bot['quantity']

        # ── REPEAT check runs unconditionally — API call failures must not prevent it ──
        repeats_done_now = bot.get('repeats_done', 0) + 1
        bot['repeats_done'] = repeats_done_now
        repeat_total = bot.get('repeat_count', 0)
        # Estimate P&L from posted prices for smart mode (actual verified later)
        _est_yes = bot.get('yes_price', 50)
        _est_no = bot.get('no_price', 50)
        _est_pnl = (100 - _est_yes - _est_no) * qty - kalshi_fee_cents(_est_yes, _est_no, qty)
        _smart_repeat, _smart_reason = _smart_mode_should_repeat(bot, _est_pnl)
        will_repeat = _smart_repeat if _smart_repeat is not None else (repeats_done_now <= repeat_total)

        bot['completed_at'] = now
        bot['status'] = 'waiting_repeat' if will_repeat else 'completed'
        bot['_just_completed'] = True
        # Capture latency BEFORE clearing for run history
        _saved_raw_hedge_ms = bot.get('raw_hedge_ms')
        _saved_hedge_latency_ms = bot.get('hedge_latency_ms')
        if will_repeat:
            bot['waiting_repeat_since'] = time.time() + 3  # 3s linger
            bot['first_fill_at'] = None
            bot['first_leg'] = None
            bot['dog_filled_at'] = None
            if bot.get('raw_hedge_ms') is not None:
                bot['_last_raw_hedge_ms'] = bot['raw_hedge_ms']
            if bot.get('hedge_latency_ms') is not None:
                bot['_last_hedge_latency_ms'] = bot['hedge_latency_ms']
            bot['raw_hedge_ms'] = None
            bot['hedge_latency_ms'] = None
            bot['fav_order_id'] = None
            bot['fav_fill_qty'] = 0
            bot['dog_fill_qty'] = 0
            bot['yes_fill_qty'] = 0
            bot['no_fill_qty'] = 0
            bot['_hedge_fired'] = False
            bot['_trade_recorded'] = False
            # Restore original qty if reduced by partial fill
            if bot.get('_original_qty'):
                bot['quantity'] = bot['_original_qty']
                bot.pop('_original_qty', None)
            bot.pop('_partial_hedge_qty', None)
            print(f'🔄 WS REPEAT: {bot_id} entering waiting_repeat — cycle {repeats_done_now}/{repeat_total}')

        # Record trade + P&L — wrapped separately so failures don't break repeat logic
        try:
            actual_yes = get_actual_fill_price(bot['yes_order_id'], 'yes')
            actual_no  = get_actual_fill_price(bot['no_order_id'], 'no')
            real_yes = actual_yes if actual_yes else bot['yes_price']
            real_no  = actual_no  if actual_no  else bot['no_price']
            fee = kalshi_fee_cents(real_yes, real_no, qty)
            profit_cents = (100 - real_yes - real_no) * qty - fee

            session_pnl['gross_profit_cents'] += profit_cents
            session_pnl['completed_bots']     += 1
            bot['net_pnl_cents'] = bot.get('net_pnl_cents', 0) + profit_cents

            _record_trade({
                'bot_id': bot_id, 'ticker': ticker,
                'yes_price': real_yes, 'no_price': real_no,
                'original_yes': bot['yes_price'], 'original_no': bot['no_price'],
                'quantity': qty, 'profit_cents': profit_cents,
                'fee_cents': fee,
                'result': 'completed', 'timestamp': now,
                'verified_prices': actual_yes is not None and actual_no is not None,
                'placed_at': bot.get('created_at', now),
                'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                'arb_width': bot.get('arb_width', bot.get('profit_per', 0)),
                'first_leg': bot.get('first_leg', ''),
                'fill_duration_s': round(now - bot['first_fill_at']) if bot.get('first_fill_at') else None,
                'game_phase': bot.get('game_phase', ''),
                'flip_threshold': bot.get('flip_threshold', FLIP_THRESHOLD_CENTS),
                'stop_loss_cents': bot.get('stop_loss_cents', 0),
                'game_context': _get_game_context(ticker),
                'repeats_done': repeats_done_now,
                'repeat_count': repeat_total,
                'repeat_cycle': repeats_done_now,
                'repeat_total': repeat_total + 1,
                'smart_mode': bot.get('smart_mode', False),
                'fill_source': 'ws_realtime',
            }, bot)
            bot['_trade_recorded'] = True  # Prevent monitor from double-recording
            # Record run history for frontend display (same as monitor path)
            _dog_side = bot.get('dog_side', 'yes')
            _fav_side = bot.get('fav_side', 'no' if _dog_side == 'yes' else 'yes')
            bot.setdefault('_run_history', []).append({
                'run': repeats_done_now,
                'pnl': profit_cents,
                'result': 'win' if profit_cents >= 0 else 'loss',
                'dog_price': bot.get('dog_price') or (real_yes if _dog_side == 'yes' else real_no),
                'fav_price': bot.get('fav_price') or (real_yes if _fav_side == 'yes' else real_no),
                'yes_price': real_yes, 'no_price': real_no,
                'dog_side': _dog_side,
                'qty': qty,
                'anchor_depth': bot.get('anchor_depth', 0),
                'taker': bot.get('_hedge_was_taker', False),
                'raw_hedge_ms': _saved_raw_hedge_ms,
                'hedge_latency_ms': _saved_hedge_latency_ms,
                'ts': now,
            })
            if will_repeat:
                bot['lifetime_pnl'] = bot.get('lifetime_pnl', 0) + profit_cents
                bot['net_pnl_cents'] = 0  # reset — lifetime_pnl has all history now
            bot_log('ARB_COMPLETED', bot_id, {
                'real_yes': real_yes, 'real_no': real_no, 'profit_cents': profit_cents,
                'fill_duration_s': round(now - bot['first_fill_at']) if bot.get('first_fill_at') else None,
                'source': 'ws_realtime', 'will_repeat': will_repeat,
            })
            print(f'⚡ WS COMPLETED: {bot_id} +{profit_cents}¢ (YES={real_yes}¢ NO={real_no}¢)'
                  + (f' → repeat {repeats_done_now}/{repeat_total}' if will_repeat else ' → done'))
            _audit('WS_COMPLETION', bot_id, {'ticker': ticker, 'yes_fill': bot.get('yes_fill_qty'), 'no_fill': bot.get('no_fill_qty'), 'will_repeat': will_repeat})
            _audit_position_check(bot_id, ticker, bot.get('dog_side', 'yes'), 'after_ws_completion')
            # Queue action so frontend gets confetti/sound/notification
            with _pending_ws_actions_lock:
                _pending_ws_actions.append({'bot_id': bot_id, 'action': 'completed', 'profit_cents': profit_cents})
                if will_repeat:
                    _pending_ws_actions.append({
                        'bot_id': bot_id, 'action': 'repeat_spawned',
                        'repeat_num': repeats_done_now, 'repeat_total': repeat_total,
                        'yes_price': bot.get('yes_price', 0), 'no_price': bot.get('no_price', 0),
                        'profit_per': 100 - bot.get('yes_price', 0) - bot.get('no_price', 0),
                    })
        except Exception as err:
            print(f'⚠ WS trade record failed for {bot_id}: {err} — repeat status already set, continuing')

        save_state()

        bot.pop('_ws_fill_handling', None)


